-- Volcando estructura de base de datos para myarcadezone
CREATE DATABASE IF NOT EXISTS `myarcadezone` /*!40100 DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci */ /*!80016 DEFAULT ENCRYPTION='N' */;
USE `myarcadezone`;

-- Volcando estructura para tabla myarcadezone.blog_posts
CREATE TABLE IF NOT EXISTS `blog_posts` (
  `id` int NOT NULL AUTO_INCREMENT,
  `slug` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `titulo` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `categoria` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `contenido_html` mediumtext COLLATE utf8mb4_unicode_ci,
  `imagen_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `video_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fecha` date DEFAULT NULL,
  `publicado` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Volcando datos para la tabla myarcadezone.blog_posts: ~4 rows (aproximadamente)
INSERT INTO `blog_posts` (`id`, `slug`, `titulo`, `categoria`, `contenido_html`, `imagen_url`, `video_url`, `fecha`, `publicado`, `created_at`) VALUES
	(5, 'El templo de los cinco duros', 'El templo de los cinco duros: por qué los recreativos eran el mejor lugar del mundo', 'NOSTALGIA-ARCADE', '<p>Había un ritual. Lo hacías sin pensarlo, igual que respirar. Cambiar el billete de cien pesetas en la máquina de cambio, escuchar el <em>clonc-clonc-clonc</em> de las monedas cayendo, y sentir ese peso en el bolsillo del pantalón. Cuatro fichas de cinco duros. Cuatro oportunidades. Cuatro pequeños soles de metal que ya sabías que ibas a perder, pero que en ese momento te hacían sentir rico como un rey.</p>\r\n\r\n<p>Bienvenido al recreativo.</p>\r\n\r\n<hr>\r\n\r\n<h2>La catedral del barrio</h2>\r\n\r\n<p>El salón recreativo no era solo un sitio con máquinas. Era <strong>el sitio</strong>. El punto de encuentro donde convergía todo lo que importaba cuando tenías entre 8 y 16 años: la adrenalina, el pique, el respeto ganado a pulso y, si eras listo, también algún crédito gratis que no le ibas a contar a nadie.</p>\r\n\r\n<p>Olía a tabaco, a fritanga del bar de al lado y a plástico caliente. La iluminación era cutre, los suelos pegajosos y la música sonaba a un volumen que no dejaba pensar. Y aun así, en invierno con el frío que hacía, no había lugar más cálido ni más vivo en todo el barrio.</p>\r\n\r\n<p>La gente no iba solo a jugar. Iba a <em>estar</em>. Y a veces ni siquiera a eso: había quien se acercaba simplemente para ver si estaba la chica que le gustaba. Porque si estaba en algún sitio, probablemente sería allí, echando una partida al Tetris con esa concentración que te dejaba sin palabras. Y si por mala suerte no aparecía, siempre quedaba el futbolín: esas largas rondas de "pierde y paga" en las que entraban y salían parejas sin parar. Si eras bueno y tenías algo de suerte —y yo tenía un poco de ambas— podías pasarte una tarde entera jugando por solo 25 pesetas.</p>\r\n\r\n<hr>\r\n\r\n<h2>El ecosistema humano de los recres</h2>\r\n\r\n<p>Si algún biólogo de los años 90 hubiera estudiado los recreativos como hábitat natural, habría descubierto un ecosistema perfectamente organizado.</p>\r\n\r\n<p><strong>El crack.</strong> El tío que se pasaba las máquinas con cinco duros mientras todo el mundo miraba con la boca abierta. Tenía los movimientos memorizados, no sudaba, no se inmutaba. Cuando llegaba el Stage 6, sacaba un crédito de la nada como un mago y seguía. Era un dios mortal.</p>\r\n\r\n<p><strong>El pelma con consejos.</strong> Invariablemente aparecía a tu espalda en el momento menos oportuno. "Salta. Ahora a la izquierda. Coge ese ítem. Que te matan, que te matan." No jugaba. Solo comentaba. Como un árbitro de fútbol que nunca ha tocado un balón. Si hubiera forma de llegar a través del tiempo, muchos lo estrangularíamos con cariño.</p>\r\n\r\n<p><strong>El chulo de los cinco duros.</strong> Mayor que tú, con la chaqueta de cuero y la novia aparcada en un futbolín. Se ponía al lado cuando llevabas diez minutos jugando bien y soltaba el clásico: "¿Me dejas la última vida que te la paso?". Le dabas la vida. La perdía en cuarenta segundos. Se encogía de hombros. Se iba. Tú te quedabas mirando la pantalla de GAME OVER con el alma partida en dos.</p>\r\n\r\n<p><strong>El mirón.</strong> Podías llevar horas jugando y él seguía ahí, a tu espalda, sin despeinarse. No metía una peseta. Ni una. Algunos porque no las tenían, otros porque habían tomado la decisión adulta de invertir su paga en una bolsa de Triskis o Risketos —no había cosa en el mundo que pringase más los dedos que unos Risketos, lo cual era un problema serio cuando luego intentabas manejar un joystick— o directamente en gominolas. El mirón era un espectador nato, un alma contemplativa en un mundo de acción. Y en el fondo, todos lo entendíamos.</p>\r\n\r\n<p><strong>El encargado.</strong> Criatura incomprendida. A veces era un señor mayor que no sabía lo que era un joystick pero que te apagaba la máquina si llevabas demasiado rato. A veces era un tipo que te miraba con ojillos de águila desde detrás del mostrador. Nunca era tu amigo. Pero tampoco era completamente tu enemigo, porque si el local iba bien, ponían máquinas nuevas, y eso lo cambiaba todo.</p>\r\n\r\n<hr>\r\n\r\n<h2>El día que llegó una máquina nueva</h2>\r\n\r\n<p>Nada —y digo absolutamente nada— igualaba la emoción de llegar al recreativo y ver una máquina tapada con una lona. O una furgoneta aparcada en la puerta descargando algo enorme. Se formaban corrillos. Se especulaba. "Dicen que es de lucha." "Que tiene pistola." "Que los gráficos son una bestialidad."</p>\r\n\r\n<p>Cuando por fin la encendían, el primer crédito era sagrado. Nadie sabía hacer nada. Todos los movimientos fallaban. La gente blasfemaba, preguntaba a gritos cómo se hacían los especiales y guardaba el secreto como si fuera la fórmula de la Coca-Cola.</p>\r\n\r\n<p>Street Fighter II llegó así. Una tarde normal, una máquina nueva, dos joysticks y seis botones que no entendía nadie. Una semana después, cada recreativo de España era un campo de batalla lleno de chavales intentando hacer el Hadouken y sacando el brazo en diagonal hacia la pantalla como si el movimiento físico fuera a ayudar.</p>\r\n\r\n<hr>\r\n\r\n<h2>El mechero, el magic clip y la ingeniería del pobre</h2>\r\n\r\n<p>La economía de los recreativos era despiadada. Cinco duros por partida, paga semanal limitada, y las ganas de jugar inversamente proporcionales al dinero disponible. Así nació la creatividad.</p>\r\n\r\n<p>El truco del mechero era el más famoso. Abrías uno de esos mecheros baratos de ferretería, sacabas el mecanismo del piezoeléctrico, lo acercabas a la ranura de monedas de ciertas máquinas y le dabas al botón. Si tenías suerte y la máquina era la adecuada, aparecía un crédito de la nada como por arte de magia. Si no tenías suerte, te llevabas un calambrazo que recordabas el resto del día.</p>\r\n\r\n<p>No funcionaba en todas las máquinas. No siempre funcionaba. Pero la <em>posibilidad</em> de que funcionara era suficiente para que toda una generación se pasara las tardes intentándolo con la cara de concentración de un cirujano.</p>\r\n\r\n<p>Había quien lo había perfeccionado hasta el punto de llevar cables escondidos bajo la ropa. Ingenieros del fraude recreativo. Pioneros incomprendidos.</p>\r\n\r\n<hr>\r\n\r\n<h2>El ocaso</h2>\r\n\r\n<p>Llegó la PlayStation. Llegaron los cibercafés. Las máquinas dejaron de renovarse. Los locales empezaron a llenarse de un ambiente que ya no invitaba a quedarse. Los encargados pusieron tragaperras donde antes había futbolines.</p>\r\n\r\n<p>Y un día, sin que nadie lo anunciara, los recreativos cerraron. Algunos se convirtieron en tiendas de chinos. Otros en bares sin personalidad. Muchos simplemente desaparecieron.</p>\r\n\r\n<p>Lo que no desapareció fue el recuerdo de esas tardes. El peso de las monedas en el bolsillo. El olor a plástico caliente. La concentración absoluta frente a una pantalla que no tenía pausa, no tenía guardado y no perdonaba.</p>\r\n\r\n<p>Y la lección fundamental que los recreativos enseñaron a toda una generación: <strong>que perder duele más cuando te ha costado cinco duros de tu propio bolsillo</strong>.</p>\r\n\r\n<hr>\r\n\r\n<blockquote>¿Tienes tu propia historia de los recreativos? Cuéntala en los comentarios. Mecheros, pajaritos, créditos robados y enemigos eternos, todo bienvenido.</blockquote>', '\\assets\\images\\Recreativos.png', '', '2026-04-28', 1, '2026-04-28 20:53:10'),
	(6, 'arcades-mas-jugados-todos-los-tiempos', 'Los 10 arcades más jugados de todos los tiempos: las máquinas que se tragaron más monedas que ninguna otra', 'HISTORIA · ARCADE', '<p>Hay máquinas que estaban en todos los recreativos. En el de tu barrio, en el del pueblo de verano, en la gasolinera de la autopista y en el bar de la esquina. Máquinas que no necesitaban que nadie te explicara cómo funcionaban porque en cuanto las veías ya sabías lo que tenías que hacer. Estas son las que más monedas se tragaron en la historia del arcade.</p>\r\n\r\n<hr>\r\n\r\n<h2>1. Pac-Man (1980) — Namco</h2>\r\n\r\n<p>El juego más reconocible de la historia. Namco vendió más de <strong>400.000 unidades</strong> de la máquina original, una cifra que no ha igualado ningún otro arcade antes ni después. En su primer año de operación en Estados Unidos recaudó más de <strong>1.000 millones de dólares en monedas de 25 centavos</strong>.</p>\r\n\r\n<p>Lo que hizo diferente a Pac-Man fue su público: por primera vez las chicas jugaban tanto como los chicos. Toru Iwatani diseñó un juego sin violencia, con un protagonista simpático y reglas inmediatamente comprensibles. El resultado fue el primer fenómeno de masas del videojuego.</p>\r\n\r\n<hr>\r\n\r\n<h2>2. Space Invaders (1978) — Taito</h2>\r\n\r\n<p>Antes de Space Invaders los salones recreativos existían, pero eran otra cosa. Después de Space Invaders, el arcade tal como lo conocemos nació. Taito tuvo que fabricar monedas de 100 yenes adicionales en Japón porque el juego las agotaba <em>literalmente</em> de circulación.</p>\r\n\r\n<p>El concepto era brutalmente simple: filas de alienígenas que bajan, tú que disparas. Pero la tensión que generaba —la música acelerándose, los invasores bajando más rápido— era adictiva de una manera que nadie había experimentado antes.</p>\r\n\r\n<hr>\r\n\r\n<h2>3. Street Fighter II (1991) — Capcom</h2>\r\n\r\n<p>Street Fighter II no inventó los juegos de lucha, pero los reinventó completamente. Capcom vendió <strong>200.000 cabinets</strong> y recaudó más de <strong>1.500 millones de dólares</strong> en sus primeros años. En los recreativos españoles de 1991 y 1992 era imposible encontrar una máquina libre en hora punta.</p>\r\n\r\n<p>Lo que lo hizo adictivo fue la profundidad disfrazada de simplicidad: cualquiera podía jugar, pero dominar a Ryu, Guile o Chun-Li requería semanas. El Hadouken que todos intentaban hacer moviendo el brazo físicamente hacia la pantalla. Los ocho personajes con estilos completamente distintos. El primer juego donde perdías y querías volver a intentarlo inmediatamente.</p>\r\n\r\n<hr>\r\n\r\n<h2>4. Donkey Kong (1981) — Nintendo</h2>\r\n\r\n<p>El juego que lanzó a Mario al mundo —entonces llamado Jumpman— y el primero en contar una historia real dentro de una máquina arcade. Un carpintero sube por andamios, salta barriles y rescata a una chica de un gorila gigante. Absurdo. Perfecto.</p>\r\n\r\n<p>Donkey Kong fue el primer gran éxito de Nintendo fuera de Japón y el juego que convenció a la industria americana de que los japoneses habían llegado para quedarse. Más de <strong>132.000 cabinets</strong> vendidos en todo el mundo.</p>\r\n\r\n<hr>\r\n\r\n<h2>5. Galaga (1981) — Namco</h2>\r\n\r\n<p>La evolución de Galaxian, que era la evolución de Space Invaders. Galaga añadió el movimiento en formación de los enemigos, los patrones de ataque memorables y el truco del doble disparo —dejar que te capturen y luego rescatar tu nave— que se convirtió en la primera estrategia avanzada que los jugadores de arcade aprendieron a dominar.</p>\r\n\r\n<p>Sigue siendo el arcade más jugado en los bares americanos que conservan máquinas clásicas. Cincuenta años después, sigue siendo perfecto.</p>\r\n\r\n<hr>\r\n\r\n<h2>6. Mortal Kombat (1992) — Midway</h2>\r\n\r\n<p>Si Street Fighter II era técnica, Mortal Kombat era espectáculo puro. Los fatalities —los movimientos de ejecución final que escandalizaron a padres y políticos de medio mundo— eran la razón por la que la cola frente a la máquina no desaparecía nunca. Todo el mundo quería ver qué pasaba cuando ganabas.</p>\r\n\r\n<p>Midway consiguió algo que pocos juegos logran: ser noticia en los telediarios. La polémica fue la mejor publicidad posible.</p>\r\n\r\n<hr>\r\n\r\n<h2>7. Out Run (1986) — Sega</h2>\r\n\r\n<p>No era un juego de carreras al uso. Era una <em>fantasía</em>. Ferrari Testarossa roja descapotable, chica en el asiento del copiloto, carreteras de postal europeo y la posibilidad de elegir la música que sonaba en la radio. Out Run vendió el sueño de la libertad en forma de joystick y dos pedales.</p>\r\n\r\n<p>Yu Suzuki diseñó los escenarios basándose en un viaje real en coche por Europa. Se nota. Cada pantalla parece un lugar al que querrías ir.</p>\r\n\r\n<hr>\r\n\r\n<h2>8. Frogger (1981) — Konami</h2>\r\n\r\n<p>Una rana cruzando una carretera y luego un río. Sin disparos, sin lucha, sin historia. Solo coordinación y timing. Frogger fue uno de los primeros juegos en demostrar que la premisa más simple podía generar la mayor adicción.</p>\r\n\r\n<p>Konami vendió más de <strong>135.000 cabinets</strong> y el juego se convirtió en uno de los primeros en tener presencia masiva fuera de los salones recreativos, en bares, restaurantes y gasolineras de todo el mundo.</p>\r\n\r\n<hr>\r\n\r\n<h2>9. Final Fight (1989) — Capcom</h2>\r\n\r\n<p>El beat \'em up definitivo. Haggar, Cody y Guy contra la banda Mad Gear en las calles de Metro City. Final Fight estableció todas las reglas del género que después seguirían Double Dragon, Streets of Rage y Cadillacs and Dinosaurs: scroll lateral, tres personajes con estilos distintos, jefes al final de cada nivel y cooperativo para dos jugadores.</p>\r\n\r\n<p>En los recreativos españoles de 1990 era el juego que siempre tenía cola. Siempre.</p>\r\n\r\n<hr>\r\n\r\n<h2>10. Tekken (1994) — Namco</h2>\r\n\r\n<p>Namco respondió a Street Fighter II y Mortal Kombat con algo diferente: combate en 3D, cuatro botones para los cuatro miembros del cuerpo y una profundidad técnica que los jugadores hardcore devoraron. Tekken llegó al final de la era dorada del arcade pero se convirtió en uno de sus últimos grandes fenómenos.</p>\r\n\r\n<p>La saga sigue viva hoy. Pocos juegos de 1994 pueden decir lo mismo.</p>\r\n\r\n<hr>\r\n\r\n<p>Esta lista podría tener cincuenta entradas. Quedan fuera Centipede, Asteroids, Defender, Time Crisis, Dance Dance Revolution... El arcade fue durante veinte años el laboratorio donde se inventó todo lo que hoy damos por sentado en los videojuegos. Cada moneda que metiste en una de estas máquinas fue un pequeño voto por lo que vino después.</p>\r\n\r\n<p><em>¿Cuál es tu favorita? ¿Cuál añadirías a la lista? Los comentarios son tuyos.</em></p>', '\\assets\\images\\Mejoresjuegos.png', '', '2026-05-03', 1, '2026-05-03 16:38:06'),
	(7, 'pinballs-mas-legendarios-todos-los-tiempos', 'Los 10 pinballs más legendarios de todos los tiempos: las mesas que se tragaron más monedas que ninguna otra', 'PINBALL · HISTORIA', '<p>El pinball no es un videojuego. Es algo anterior, algo más físico, algo que ninguna pantalla ha conseguido replicar del todo. La bola de acero rodando por la madera, el golpe seco de los flippers, el ruido de los bumpers encadenándose... Hay mesas que llevan décadas en bares, recreativos y sótanos de coleccionistas y que siguen tragándose monedas con la misma eficiencia que el primer día. Estas son las diez más legendarias.</p>\r\n\r\n<hr>\r\n\r\n<h2>1. The Addams Family (1992) — Williams</h2>\r\n\r\n<p>El número es inapelable: <strong>20.270 unidades fabricadas</strong>. Ningún pinball en la historia ha vendido más. Diseñado por Pat Lawlor, con voces reales de Raul Julia y Anjelica Huston, La Cosa saliendo de su caja y 13 modos de juego con Wizard Mode. The Addams Family no solo es el más vendido — es el que más gente ha convertido en aficionada al pinball sin haberlo buscado.</p>\r\n\r\n<p>Si solo puedes jugar a uno en tu vida, que sea este.</p>\r\n\r\n<hr>\r\n\r\n<h2>2. Medieval Madness (1997) — Williams</h2>\r\n\r\n<p>El favorito absoluto de los coleccionistas. Pat Lawlor otra vez, con una mesa que tiene castillos que se destruyen físicamente, trolls que aparecen, catapultas y un humor absurdo que hace que cada partida sea diferente. Técnicamente es una obra maestra — el sistema de castillos con mecanismo físico no lo había intentado nadie antes — y el resultado es la mesa más divertida que Williams jamás produjo.</p>\r\n\r\n<p>Los precios en el mercado de coleccionismo llevan años subiendo sin parar. Hay razones para ello.</p>\r\n\r\n<hr>\r\n\r\n<h2>3. The Twilight Zone (1993) — Williams</h2>\r\n\r\n<p>La mesa más compleja de la historia del pinball. Pat Lawlor de nuevo — en su mejor racha creativa — con 12 modos de juego, un mini-playfield dentro de la mesa, una bola magnética controlada por electroimanes y unas reglas tan profundas que los jugadores veteranos siguen descubriendo cosas después de años. La serie de televisión de Rod Serling nunca imaginó que acabaría en una mesa de pinball. El resultado es sublime.</p>\r\n\r\n<hr>\r\n\r\n<h2>4. Theatre of Magic (1995) — Bally</h2>\r\n\r\n<p>Steve Ritchie diseñó mesas rápidas. Pat Lawlor diseñó mesas profundas. John Popadiuk diseñó mesas <em>mágicas</em>. Theatre of Magic tiene un baúl en el centro que atrapa la bola y la dispara en distintas direcciones según el modo, un espejo que refleja el playfield completo y una atmósfera de ilusionismo que ninguna otra mesa ha igualado.</p>\r\n\r\n<p>No es la más vendida ni la más compleja, pero es la más elegante. Y en pinball, la elegancia importa.</p>\r\n\r\n<hr>\r\n\r\n<h2>5. Terminator 2: Judgment Day (1991) — Williams</h2>\r\n\r\n<p>Steve Ritchie capturó el furor de la película de Cameron con una mesa que en 1991 era técnicamente imposible para sus competidores. El cañón de plasma — un lanzador secundario que dispara la bola por la parte superior del playfield — fue el primer mecanismo de este tipo en un pinball de producción masiva. Más de <strong>15.000 unidades vendidas</strong>, lo que lo convierte en el segundo pinball más vendido de Williams.</p>\r\n\r\n<p>Funciona igual de bien en 2024 que en 1991. Las mesas buenas no envejecen.</p>\r\n\r\n<hr>\r\n\r\n<h2>6. Attack from Mars (1995) — Bally</h2>\r\n\r\n<p>Brian Eddy diseñó la mesa más accesible de esta lista. Los marcianos invaden la Tierra, tú los rechazas a base de flippers. El humor es absurdo, los sonidos son memorables y el Wizard Mode — <strong>Rule the Universe</strong> — es el más satisfactorio de conseguir de todos los pinballs de los 90. Hay coleccionistas que tienen tres.</p>\r\n\r\n<hr>\r\n\r\n<h2>7. The Flintstones (1994) — Williams</h2>\r\n\r\n<p>Steve Ritchie con licencia de Hanna-Barbera y voces digitalizadas de los actores de la película de 1994. La mesa más familiar de la lista — accesible para cualquier edad — con un juego más profundo de lo que la licencia hace prever. El Bedrock Express, La Cosa... espera, eso era otra mesa. Aquí es el Dino y el Quarry. Más de <strong>5.000 unidades</strong> que siguen funcionando en bares de toda Europa.</p>\r\n\r\n<hr>\r\n\r\n<h2>8. Bride of Pinbot (1991) — Williams</h2>\r\n\r\n<p>La secuela de Pinbot — una de las mesas más icónicas de los 80 — llegó con una novedad que nadie esperaba: un objetivo femenino que se iba construyendo a medida que jugabas. Primero los ojos, luego la cara, luego el cuerpo completo. Era narrativa dentro de una mesa de pinball, algo que en 1991 era revolucionario. El mecanismo de la cabeza giratoria es uno de los más imitados de la historia.</p>\r\n\r\n<hr>\r\n\r\n<h2>9. Indiana Jones: The Pinball Adventure (1993) — Williams</h2>\r\n\r\n<p>Steve Ritchie otra vez, con la licencia más épica posible. Tres películas condensadas en una mesa: el Arca de la Alianza, el Templo Maldito, el Santo Grial. Los modos se activan en orden cronológico por película y la acumulación de objetivos da una sensación de aventura que pocas mesas han conseguido. La música de John Williams ayuda considerablemente.</p>\r\n\r\n<hr>\r\n\r\n<h2>10. Scared Stiff (1996) — Bally</h2>\r\n\r\n<p>La continuación espiritual de Elvira and the Party Monsters, con Elvira presentando cada modo con ese humor de serie B que es exactamente lo que el pinball necesitaba a mediados de los 90. Scared Stiff tiene el mejor multibola de la lista — <strong>Stiff-O-Meter Multiball</strong> — y una personalidad visual que hace que cualquier partida parezca un capítulo de una serie de terror de los 80 que nunca existió pero debería haber existido.</p>\r\n\r\n<hr>\r\n\r\n<p>Lo que tienen en común estas diez mesas es que ninguna necesita explicación. Las ves encendidas en un bar o en un recreativo y ya sabes lo que tienes que hacer. Metes la moneda, lanzas la bola y el resto pasa solo.</p>\r\n\r\n<p>El pinball lleva muerto desde los años 90 según la gente que no entiende de pinball. Las mesas de esta lista siguen funcionando, siguen tragándose monedas y siguen convirtiendo a nuevos aficionados cada día. Hay cosas que simplemente no mueren.</p>\r\n\r\n<p><em>¿Cuál es tu mesa favorita? ¿Falta alguna en esta lista? Los comentarios son tuyos.</em></p>', '\\assets\\images\\Blogpinball.jpg', '', '2026-05-04', 1, '2026-05-04 20:02:23'),
	(8, 'mejores-pinballs-fabricados-en-espana', 'Los mejores pinballs fabricados en España: una industria que el mundo no conoce', 'HISTORIA', '<p>Cuando hablas de pinball, todo el mundo piensa en <strong>Williams</strong>. En <strong>Bally</strong>. En <strong>Stern</strong>. En las grandes fábricas de Chicago que dominaron el mercado mundial durante décadas. Lo que muy poca gente sabe —y aquí está la gracia del asunto— es que <strong>España tuvo su propia industria pinballera</strong>. Una industria real, con fabricantes serios, máquinas exportadas a toda Europa y un catálogo que merece mucho más reconocimiento del que tiene.</p>\r\n\r\n<p>Entre los años 70 y los 90, un puñado de empresas españolas —la mayoría catalanas— fabricaron cientos de modelos que llegaron a bares, salones recreativos y locales de toda la península y más allá. No eran copias baratas de los americanos. Eran <strong>diseños propios</strong>, con su propio hardware, su propia electrónica y, en algunos casos, una personalidad muy particular.</p>\r\n\r\n<p>Este es el repaso que nadie ha hecho todavía en español.</p>\r\n\r\n<hr>\r\n\r\n<h2>EL PETACO — JUEGOS POPULARES · Madrid, años 80</h2>\r\n\r\n<p>Empezamos por el que todos conocéis aunque no sepáis su nombre. <em>El Petaco</em>. Si creciste en España en los años 80 y frecuentaste algún bar, cafetería o salón de juegos, lo has visto. Era ese pinball compacto, más pequeño que los americanos, con una mecánica simplificada y un precio de crédito ajustado para el bolsillo de cualquier parroquiano.</p>\r\n\r\n<p><strong>Juegos Populares</strong>, empresa madrileña, entendió perfectamente el mercado español: no necesitabas una máquina enorme y cara para poner en el bar del barrio. Necesitabas algo asequible, robusto y que metiera monedas. El Petaco lo hizo durante años y se convirtió en un icono de la hostelería española que todavía hoy genera una nostalgia irracional en cualquiera que lo mencione.</p>\r\n\r\n<blockquote>No era el pinball más sofisticado del mundo. Pero era el nuestro. Y eso vale más que cualquier licencia americana.</blockquote>\r\n\r\n<hr>\r\n\r\n<h2>PEYPER — Barcelona · 1981–1993</h2>\r\n\r\n<p>Si hay una empresa española que merece estar en cualquier conversación seria sobre pinball europeo, esa es <strong>Peyper</strong>. Fundada en Barcelona, llegó a ser uno de los fabricantes más activos del continente durante los años 80. Sus máquinas tenían un acabado serio, electrónica propia y una estética que mezclaba la energía del arcade con las temáticas de moda de la época.</p>\r\n\r\n<p><strong>Odin (1985)</strong> es probablemente su obra más reconocida entre los coleccionistas actuales. Temática de mitología nórdica, campo de juego bien diseñado, electrónica sólida. Si buscas una máquina española para coleccionar, el Odin siempre aparece en las listas cortas.</p>\r\n\r\n<p><strong>Ator (1984)</strong>, inspirada en el personaje de película de serie B del mismo nombre, es un ejemplo perfecto de lo que hacía Peyper bien: coger una licencia de segunda fila y montarle encima una máquina entretenida y funcional.</p>\r\n\r\n<p><strong>Wolf Man (1987)</strong> llegó en plena fiebre del terror ochentero y aprovechó la ola. Estética oscura, buena jugabilidad, y una de las últimas grandes apuestas de la empresa antes de que el mercado empezara a complicarse.</p>\r\n\r\n<p><strong>Roller Aces (1987)</strong> y <strong>Nightflight (1989)</strong> completaron su catálogo final. Peyper cerró a principios de los 90 cuando el mercado del pinball entró en crisis general, pero dejó un legado que los coleccionistas europeos todavía rastrean con devoción.</p>\r\n\r\n<hr>\r\n\r\n<h2>PLAYMATIC — Barcelona · 1970–1985</h2>\r\n\r\n<p><strong>Playmatic</strong> es probablemente el fabricante español más prolífico de todos. Empezaron en los años 70 con máquinas electromecánicas y evolucionaron hacia los sistemas de estado sólido cuando la industria lo exigió. En su momento de máxima producción llegaron a fabricar decenas de modelos distintos.</p>\r\n\r\n<p><strong>Evil Fight (1980)</strong> es su máquina más recordada. Temática de artes marciales —absolutamente de época—, electrónica propia y una jugabilidad directa que funcionaba muy bien en el entorno de bar. Es de esas máquinas que, cuando la ves restaurada en una foto, te genera un reconocimiento inmediato aunque nunca supieras su nombre.</p>\r\n\r\n<p><strong>Meg-Aaton (1984)</strong> fue una de sus últimas apuestas fuertes, con temática de ciencia ficción y un diseño más ambicioso que reflejaba los años de experiencia acumulados. Para entonces Playmatic ya competía directamente con los americanos en calidad de acabado.</p>\r\n\r\n<p><strong>Quick Silver (1983)</strong> y <strong>Blackball (1984)</strong> son otros títulos que aparecen constantemente en los inventarios de coleccionistas. Playmatic tuvo un final abrupto a mediados de los 80 —combinación de crisis del sector, competencia americana y problemas internos— pero durante quince años fue la empresa más seria que tuvo España en este mercado.</p>\r\n\r\n<hr>\r\n\r\n<h2>INDER — Bilbao · años 80</h2>\r\n\r\n<p><strong>Inder</strong> es el caso menos conocido de los tres grandes, pero no por eso menos interesante. Empresa vasca que fabricó pinballs durante los años 80 con una línea estética propia y resultados notables.</p>\r\n\r\n<p><strong>Brave Team (1985)</strong> es su título estrella: temática militar, campo de juego dinámico y una construcción robusta que ha hecho que muchos ejemplares hayan sobrevivido hasta hoy en buen estado. Entre los coleccionistas españoles es una de las máquinas más buscadas precisamente porque está bien hecha y representa algo propio.</p>\r\n\r\n<p><strong>Corsario (1986)</strong> siguió la estela con temática de piratas, aprovechando que en ese año todo el mundo quería sacar algo con espadas y barcos. Correcta en todos sus aspectos, sin llegar a ser revolucionaria.</p>\r\n\r\n<p>Lo que distinguía a Inder era la <strong>robustez</strong>. Máquinas pensadas para aguantar, construidas con criterio industrial. Quizás por eso todavía aparecen ejemplares en buen estado con más frecuencia que los de otros fabricantes.</p>\r\n\r\n<hr>\r\n\r\n<h2>POR QUÉ IMPORTA ESTO</h2>\r\n\r\n<p>España nunca debería haber tenido industria pinballera. Éramos un mercado periférico, con menos poder adquisitivo que los grandes países europeos, sin tradición en fabricación de electrónica de entretenimiento y dependientes de lo que llegaba de fuera.</p>\r\n\r\n<p>Y aun así, durante veinte años, un grupo de empresas catalanas y vascas fabricó máquinas que se vendieron en <strong>Francia, Alemania, Italia y el Reino Unido</strong>. Máquinas con diseño español, electrónica española, que competían —no siempre en igualdad de condiciones, pero competían— con los grandes americanos.</p>\r\n\r\n<p>Es una historia que casi nadie cuenta. Y es una lástima, porque cuando la conoces, te cambia un poco la perspectiva sobre lo que fue capaz de hacer la industria de este país cuando nadie la miraba.</p>\r\n\r\n<blockquote>La próxima vez que veas un pinball antiguo en un bar de pueblo, antes de pasar de largo, mira la placa del fabricante. Igual te llevas una sorpresa.</blockquote>', '\\assets\\images\\PInballspain.png', '', '2026-05-05', 1, '2026-05-05 20:56:31');

