  `titulo` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `desarrollador` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `publisher` varchar(300) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `anno` smallint DEFAULT NULL,
  `genero` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `plataforma_original` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `plataformas` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `descripcion_corta` text COLLATE utf8mb4_unicode_ci,
  `nota` decimal(3,1) DEFAULT NULL,
  `badge_tipo` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `badge_texto` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `audio_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `audio_titulo` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `video_youtube` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `imagen_cover` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `veredicto_texto` text COLLATE utf8mb4_unicode_ci,
  `pros` text COLLATE utf8mb4_unicode_ci,
  `contras` text COLLATE utf8mb4_unicode_ci,
  `links_html` text COLLATE utf8mb4_unicode_ci,
  `publicada` tinyint(1) NOT NULL DEFAULT '0',
  `fecha_publicacion` date DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Volcando datos para la tabla myarcadezone.juegos: ~7 rows (aproximadamente)
INSERT INTO `juegos` (`id`, `slug`, `titulo`, `desarrollador`, `publisher`, `anno`, `genero`, `plataforma_original`, `plataformas`, `descripcion_corta`, `nota`, `badge_tipo`, `badge_texto`, `audio_url`, `audio_titulo`, `video_youtube`, `imagen_cover`, `veredicto_texto`, `pros`, `contras`, `links_html`, `publicada`, `fecha_publicacion`, `created_at`) VALUES
	(1, 'street-fighter-ii', 'Street Fighter II', 'Capcom', 'Capcom', 1991, 'Lucha', 'Arcade CPS-I', 'SNES, Mega Drive, PC Engine, PS1, Saturn, GBA', 'El juego de lucha que lo cmabió todo', 9.0, 'destacada', 'RESEÑA DESTACADA', 'https://ia601604.us.archive.org/2/items/street-fighter-ii-arcade-music-ryu-stage-cps-1/Street%20Fighter%20II%20Arcade%20Music%20-%20Ryu%20Stage%20-%20CPS1.mp3', 'Street Fighter II Arcade Music - Ryu Stage - CPS1', 'https://www.youtube.com/watch?v=6OlenbCC4WI', '/assets/images/sf2_cover.jpeg', 'Street Fighter II no es solo un gran juego: es el Big Bang del género de lucha. \r\nAntes de él existían juegos de pelea, pero ninguno había combinado de forma \r\ntan perfecta el elenco de personajes, la profundidad técnica y la jugabilidad \r\ninmediata. Treinta años después sigue siendo el referente con el que se mide \r\ntodo lo demás.', 'Sistema de lucha profundo y accesible a la vez\r\n8 personajes con estilos radicalmente distintos\r\nMúsica que se te queda grabada para siempre\r\nGráficos espectaculares para 1991\r\nRejugabilidad infinita\r\nDefinió un género entero', 'La IA en dificultades altas hace trampas descaradas\r\nAlgunos personajes están claramente desequilibrados\r\nEl modo un jugador se queda corto', '<a href="https://www.mobygames.com/game/street-fighter-ii-the-world-warrior" target="_blank">MobyGames — Ficha técnica y capturas de todas las plataformas</a>\r\n<a href="https://streetfighter.fandom.com/wiki/Street_Fighter_II:_The_World_Warrior" target="_blank">Street Fighter Wiki — Historia completa y datos del juego</a>\r\n<a href="https://www.youtube.com/watch?v=eoMgmYsWjyI" target="_blank">YouTube — Banda sonora completa arcade original</a>', 1, '2026-04-19', '2026-04-19 20:04:07'),
	(12, 'final-fight', 'Final Fight', 'Capcom', 'Capcom', 1989, 'Beat \'em up', 'Arcade CPS-I', 'SNES, Mega-CD, GBA', 'El beat \'em up que lo cambió todo. Metro City nunca fue tan peligrosa ni tan divertida.', 9.0, 'destacada', '', 'https://ia601605.us.archive.org/20/items/final-fight-arcade-opening-theme/Final%20Fight%20%28Arcade%29%20-%20Opening%20Theme.mp3', 'Final Fight Music Arcade (Yoshihiro Sakaguchi)', 'https://www.youtube.com/watch?v=5YcfUCVcXEk', '\\assets\\images\\ffight.png', 'Final Fight no es un juego perfecto. Las versiones domésticas sufrieron recortes importantes (sin modo cooperativo en la versión SNES, personajes eliminados), y la versión arcade en solitario puede resultar despiadada con su sistema de economía de monedas. Pero en su plataforma original —la recreativa— es una obra maestra del género.', 'Sprites enormes y animación fluida para 1989\r\nSistema de combate con más profundidad de la que parece\r\nTres personajes con estilos muy diferenciados\r\nJefes memorables con patrones únicos\r\nBanda sonora de primer nivel (Yoshihiro Sakaguchi)\r\nDiseño de niveles variado en atmósfera y paleta visual', 'Versión SNES sin cooperativo y con personajes recortados\r\nMuy tragaperras en su versión recreativa original\r\nAlgo corto para jugadores experimentados', '', 1, '2026-04-24', '2026-04-24 20:34:17'),
	(14, 'pac-man', 'Pac-Man', 'Namco', 'Midway (versión USA)', 1980, 'Otros', 'Arcade (Namco Pac-Man hardware)', '', 'El juego que sacó el arcade de los bares y lo metió en el salón de tu casa. Waka waka...', 8.7, 'destacada', '', '', '', 'https://www.youtube.com/watch?v=i_OjztdQ8iw', '/assets/images/Pac-man_cover.jpg', 'El juego que inventó la cultura del arcade tal como la conocemos. No es el más difícil ni el más espectacular, pero ningún otro título ha hecho tanto con tan poco. Cuarenta años después sigue siendo perfecto.', 'Mecánica accesible para cualquiera desde el primer segundo\r\nLos cuatro fantasmas con IA propia — cada uno diferente\r\nEl diseño del laberinto es un ejercicio de equilibrio perfecto\r\nLas Power Pellets invierten la dinámica de caza en un instante\r\nEl sonido más reconocible de la historia de los videojuegos', 'La dificultad escala de forma brutal a partir del nivel 5\r\nSin fin real — solo el kill screen del nivel 256\r\nLa versión Atari 2600 fue un desastre que manchó el nombre', '<a href="https://www.arcade-museum.com/game_detail.php?game_id=9074" target="_blank">● Arcade Museum — Ficha técnica</a>\r\n<a href="https://en.wikipedia.org/wiki/Pac-Man" target="_blank">● Wikipedia — Pac-Man</a>', 1, '2026-04-27', '2026-04-27 19:01:14'),
	(15, 'cadillacs-and-dinosaurs', 'Cadillacs and Dinosaurs', 'Capcom', 'Capcom', 1992, 'Beat \'em up', 'Arcade CPS-I', '', 'Un beat \'em up de Capcom ambientado en un mundo post-apocalíptico donde los coches de los años 50 conviven con dinosaurios prehistóricos. Cuatro personajes, puños a mansalva y uno de los arcades más espectaculares de su época.', 8.8, 'destacada', '', 'https://ia902805.us.archive.org/20/items/06-cadillacs-the-four-heroes-stage-1-1-ending-2/06-Cadillacs%20-The%20Four%20Heroes-%20%28Stage%201-1%2C%20Ending%202%29.mp3', '', 'https://www.youtube.com/watch?v=eRbsZMrYEvA', '\\assets\\images\\Cadillacs.jpg', '', 'Ambientación única irrepetible, dinosaurios como arma de combate, cooperativo a cuatro jugadores, música brutal para la época, sprites enormes y detallados en CPS-1.', 'Repetitivo en solitario, jefes finales con demasiada vida que alargan el juego artificialmente, nunca tuvo segunda parte.', '', 1, '2026-05-01', '2026-05-01 17:12:43'),
	(17, 'the-flinstones', 'The Flinstones', 'Williams', 'Williams', 1994, 'Pinball', '', '', '', 8.2, 'destacada', '', 'https://ia903209.us.archive.org/7/items/the-flintstones-pinball-music/The%20Flintstones%20%28pinball%20music%29.mp3', 'The Flinstones (Pinball)', 'youtube.com/watch?v=mUOFZG-TM6s&time_continue=2&source_ve_path=NzY3NTg&embeds_referring_euri=http%3A%2F%2Fmyarcadezone.test%2F', '\\assets\\images\\flinstones.jpg', '', '', '', '', 1, '2026-05-04', '2026-05-04 06:49:09'),
	(18, 'the-addams-family-pinball', 'The Addams Family', 'Williams', 'Williams', 1992, 'Pinball', '', '', '', 9.5, 'destacada', '', 'https://ia600505.us.archive.org/17/items/the-addams-family-pinball-soundtrack/The%20Addams%20Family%20%20pinball%20Soundtrack.mp3', '', 'https://www.youtube.com/watch?v=WUSobAWbwZk', '\\assets\\images\\Addams.jpg', 'The Addams Family no es solo el pinball más vendido de la historia — es la demostración definitiva de lo que el pinball puede ser cuando todo sale bien al mismo tiempo. Licencia perfecta, diseñador en su mejor momento, tecnología de audio sin precedentes y un layout que ha resistido treinta años sin envejecer.\r\n\r\nSi alguna vez tienes la oportunidad de jugar en una máquina original en buen estado, hazlo. No importa si nunca has tocado un pinball. No importa si los videojuegos te parecen más interesantes. The Addams Family es una experiencia que trasciende el género.', 'Las voces de Raul Julia y Anjelica Huston, La Cosa como elemento interactivo, 13 modos con Wizard Mode, profundidad de reglas inagotable, icónico visualmente.', 'El precio en el mercado de coleccionismo es elevado y sigue subiendo. Las piezas originales son difíciles de conseguir.', '', 1, '2026-05-04', '2026-05-04 19:25:19'),
	(19, 'terminator-2-judgment-day', 'Terminator 2: Judgment Day', 'Williams', 'Williams', 1991, 'Pinball', '', '', 'El pinball de Steve Ritchie basado en la película de James Cameron. El cañón de plasma como lanzador secundario fue una revolución en 1991. Más de 15.000 unidades fabricadas. Una mesa que funciona igual de bien hoy que hace treinta años.', 9.2, 'destacada', '', 'https://ia903204.us.archive.org/9/items/terminator-2-judgment-day_202605/Terminator%202%20Judgment%20Day.mp3', 'Terminator 2: Judgment day', 'https://www.youtube.com/watch?v=Dqb2GX28nls', '\\assets\\images\\Terminator2.jpg', 'Terminator 2 es el pinball perfecto para quien quiere velocidad antes que profundidad. No tiene las reglas complejas de The Twilight Zone ni la narrativa de The Addams Family, pero tiene algo que esas mesas no tienen: una energía bruta e inmediata que engancha desde el primer segundo.\r\n\r\nEl cañón de plasma sigue siendo el mecanismo más satisfactorio de usar en la historia del pinball. Las voces de Schwarzenegger siguen funcionando treinta años después. Y la mesa en su conjunto sigue siendo, partida tras partida, exactamente lo que promete: una máquina de guerra. \r\nImprescindible si: Eres fan de la película, quieres una mesa rápida y directa, o buscas una T2 como primera compra de coleccionista.', 'El cañón de plasma como revolución mecánica, voces originales de Schwarzenegger, velocidad y fluidez excepcionales, backglass icónico, sistema WPC fiable.', 'Reglas más simples que otros Williams de la época, el Wizard Mode es difícil de alcanzar para jugadores casuales.', '', 1, '2026-05-05', '2026-05-05 20:20:35');

-- Volcando estructura para tabla myarcadezone.juego_personaje
CREATE TABLE IF NOT EXISTS `juego_personaje` (
  `juego_id` int NOT NULL,
  `personaje_id` int NOT NULL,
  PRIMARY KEY (`juego_id`,`personaje_id`),
  KEY `personaje_id` (`personaje_id`),
  CONSTRAINT `juego_personaje_ibfk_1` FOREIGN KEY (`juego_id`) REFERENCES `juegos` (`id`) ON DELETE CASCADE,
  CONSTRAINT `juego_personaje_ibfk_2` FOREIGN KEY (`personaje_id`) REFERENCES `personajes` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

