-- Volcando estructura para tabla myarcadezone.personajes
CREATE TABLE IF NOT EXISTS `personajes` (
  `id` int NOT NULL AUTO_INCREMENT,
  `slug` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `nombre` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `juego_origen` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sprite_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notas_html` text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`)
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Volcando datos para la tabla myarcadezone.personajes: ~16 rows (aproximadamente)
INSERT INTO `personajes` (`id`, `slug`, `nombre`, `juego_origen`, `sprite_url`, `notas_html`) VALUES
	(1, 'ryu', 'RYU', 'Street Fighter II', 'sheet|/assets/sprites/ryu-sheet.png|4|120|175', '<p class="char-bio">\r\n  Ryu es el guerrero errante por excelencia del universo de Street Fighter. Discípulo del maestro Gouken, ha dedicado su vida entera a la búsqueda de la perfección en las artes marciales. Sin hogar fijo, viaja por el mundo desafiando a los combatientes más fuertes para forjarse como luchador. Su mayor batalla, sin embargo, no es contra sus rivales: es contra el <em>Satsui no Hado</em>, la oscura energía destructiva que amenaza con consumirlo desde adentro.\r\n</p>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat"><div class="char-stat-label">Origen</div><div class="char-stat-value">Japón</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Estilo</div><div class="char-stat-value">Ansatsuken</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Maestro</div><div class="char-stat-value">Gouken</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Rival</div><div class="char-stat-value">Ken Masters</div></div>\r\n</div>\r\n\r\n<p class="char-section-title">STREET FIGHTER II</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🔥</div>\r\n    <div>\r\n      <div class="char-move-name">Hadouken</div>\r\n      <div class="char-move-input">↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Proyectil de energía ki disparado con ambas manos. El golpe más icónico de toda la saga.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">⚡</div>\r\n    <div>\r\n      <div class="char-move-name">Shoryuken</div>\r\n      <div class="char-move-input">→↓↘ + Puño</div>\r\n      <p class="char-move-desc">Uppercut ascendente devastador. Invencible en los primeros fotogramas, el antiaire definitivo.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🌀</div>\r\n    <div>\r\n      <div class="char-move-name">Tatsumaki Senpukyaku</div>\r\n      <div class="char-move-input">↓↙← + Patada</div>\r\n      <p class="char-move-desc">Patada giratoria que avanza hacia el rival. Permite cruzar la pantalla y encadenar combos.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-section-title">OTROS TÍTULOS</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Shinku Hadouken</div>\r\n      <div class="char-move-input">↓↘→↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha / SF III). Hadouken masivo que ocupa toda la pantalla. Concentra el ki máximo de Ryu en un proyectil devastador.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Shin Shoryuken</div>\r\n      <div class="char-move-input">↓↘→↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Super Art (SF III). Triple Shoryuken en un único golpe ascendente. El movimiento más poderoso de Ryu.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-quote">"No me interesa ser el más fuerte. Me interesa ser mejor que ayer." — Ryu, Street Fighter III</p>'),
	(3, 'ken', 'Ken', 'Street Fighter II', 'sheet|/assets/sprites/Ken-sprite.png|4|101|175', '<p class="char-bio">\r\n  Ken Masters es el eterno rival y mejor amigo de Ryu. Heredero de una fortuna californiana, estudió bajo el maestro Gouken junto a Ryu y dominó el mismo estilo <em>Ansatsuken</em>, aunque su versión es más agresiva, flamígera y espectacular. A diferencia del ascético Ryu, Ken disfruta de la fama, el dinero y su novia Eliza — pero cuando pisa el tatami, nadie duda de su talento. Su <em>Shoryuken</em> ardiente es considerado el más devastador de la saga.\r\n</p>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat"><div class="char-stat-label">Origen</div><div class="char-stat-value">EE.UU.</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Estilo</div><div class="char-stat-value">Ansatsuken</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Maestro</div><div class="char-stat-value">Gouken</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Rival</div><div class="char-stat-value">Ryu</div></div>\r\n</div>\r\n\r\n<p class="char-section-title">STREET FIGHTER II</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🔥</div>\r\n    <div>\r\n      <div class="char-move-name">Hadouken</div>\r\n      <div class="char-move-input">↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Proyectil de energía ki con tono anaranjado, reflejo del carácter ardiente de Ken.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🔥</div>\r\n    <div>\r\n      <div class="char-move-name">Shoryuken</div>\r\n      <div class="char-move-input">→↓↘ + Puño</div>\r\n      <p class="char-move-desc">Uppercut ascendente envuelto en llamas. Más potente y vistoso que el de Ryu — el puño de Ken arde al contacto.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🌀</div>\r\n    <div>\r\n      <div class="char-move-name">Tatsumaki Senpukyaku</div>\r\n      <div class="char-move-input">↓↙← + Patada</div>\r\n      <p class="char-move-desc">Patada giratoria ejecutada con más velocidad que Ryu, ideal para cerrar distancia.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-section-title">OTROS TÍTULOS</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Shoryu Reppa</div>\r\n      <div class="char-move-input">↓↘→↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha / SF III). Serie encadenada de Shoryukens en llamas. Sube al rival hacia el cielo ardiendo.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Shinryuken</div>\r\n      <div class="char-move-input">↓↘→↓↘→ + Patada</div>\r\n      <p class="char-move-desc">Super Art (SF III). Shoryuken giratorio que crea un tornado de fuego. Devastador en esquina.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-quote">"¡Gana o pierde, lo importante es el espectáculo!" — Ken Masters</p>'),
	(5, 'blanka', 'Blanka', 'Street Fighter II', 'sheet|/assets/sprites/Blanka-sprite.png|3|182|175', '<p class="char-bio">\r\n  Blanka es uno de los personajes más salvajes e icónicos de Street Fighter II. Criado en las selvas del Amazonas tras sobrevivir a un accidente aéreo de niño, aprendió a luchar observando a los animales y desarrolló la extraordinaria capacidad de generar <em>descargas eléctricas</em> imitando a las anguilas eléctricas del río. Su aspecto bestial esconde una historia profundamente humana: su nombre real es Jimmy, y su mayor sueño es reencontrarse con su madre.\r\n</p>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat"><div class="char-stat-label">Origen</div><div class="char-stat-value">Brasil</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Estilo</div><div class="char-stat-value">Selvático</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Habilidad</div><div class="char-stat-value">Electricidad</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Nombre real</div><div class="char-stat-value">Jimmy</div></div>\r\n</div>\r\n\r\n<p class="char-section-title">STREET FIGHTER II</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-icon">⚡</div>\r\n    <div>\r\n      <div class="char-move-name">Electric Thunder</div>\r\n      <div class="char-move-input">Machacar Puño</div>\r\n      <p class="char-move-desc">Descarga eléctrica que recubre todo su cuerpo. Cualquier rival que le toque recibe daño. Uno de los movimientos más frustrantes del juego para el oponente.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🌀</div>\r\n    <div>\r\n      <div class="char-move-name">Rolling Attack</div>\r\n      <div class="char-move-input">← carga → + Puño</div>\r\n      <p class="char-move-desc">Se hace bola y rueda a gran velocidad hacia el rival. Golpe base de su juego ofensivo — rápido, difícil de leer y devastador en el rincón.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🥊</div>\r\n    <div>\r\n      <div class="char-move-name">Up Ball</div>\r\n      <div class="char-move-input">↓ carga ↑ + Puño</div>\r\n      <p class="char-move-desc">Versión ascendente del Rolling Attack. Funciona como antiaire y permite salir de la presión del rival con un golpe sorpresivo hacia arriba.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-section-title">OTROS TÍTULOS</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Shout of Earth</div>\r\n      <div class="char-move-input">↓↘→↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Serie de Rolling Attacks encadenados a velocidad brutal. Blanka cruza la pantalla varias veces dejando al rival sin tiempo de reacción.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Lightning Cannonball</div>\r\n      <div class="char-move-input">↓↘→↓↘→ + Patada</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Rolling Attack electrificado — combina su bola rodante con descargas eléctricas continuas para un daño devastador.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-quote">"¡GRAAAAH!" — Blanka, cada vez que gana</p>'),
	(6, 'guile', 'Guile', 'Street Fighter II', 'sheet|/assets/sprites/Guile-sprite.png|5|170|175', '<p class="char-bio">\r\n  Guile es el soldado americano por excelencia del universo Street Fighter. Mayor de las Fuerzas Aéreas de los Estados Unidos, su motivación para entrar al torneo no es la gloria ni el dinero: es la venganza. Su mejor amigo Charlie Nash fue asesinado por <em>M. Bison</em>, y Guile ha jurado hacerle pagar. Disciplinado, frío y tremendamente poderoso, su estilo de lucha refleja su carácter militar — defensivo, calculado y letal cuando golpea.\r\n</p>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat"><div class="char-stat-label">Origen</div><div class="char-stat-value">EE.UU.</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Rango</div><div class="char-stat-value">Mayor USAF</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Estilo</div><div class="char-stat-value">Militar / Lucha</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Motivación</div><div class="char-stat-value">Vengar a Charlie</div></div>\r\n</div>\r\n\r\n<p class="char-section-title">STREET FIGHTER II</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-icon">💨</div>\r\n    <div>\r\n      <div class="char-move-name">Sonic Boom</div>\r\n      <div class="char-move-input">← carga → + Puño</div>\r\n      <p class="char-move-desc">Onda de presión sónica lanzada con el brazo. Proyectil rápido y de largo alcance — la columna vertebral de su juego a distancia.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🥊</div>\r\n    <div>\r\n      <div class="char-move-name">Flash Kick</div>\r\n      <div class="char-move-input">↓ carga ↑ + Patada</div>\r\n      <p class="char-move-desc">Patada ascendente en arco ejecutada desde abajo. Antiaire definitivo — invencible en los primeros fotogramas y devastador contra saltos.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-section-title">OTROS TÍTULOS</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Total Wipeout</div>\r\n      <div class="char-move-input">← carga →← → + Puño</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Serie de Sonic Booms encadenados que llenan la pantalla. Imparable a distancia media y letal como punish.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Flash Explosion</div>\r\n      <div class="char-move-input">↓ carga ↑↓ ↑ + Patada</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Triple Flash Kick encadenado que lanza al rival hacia el cielo. El finisher más espectacular del repertorio de Guile.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-quote">"Go home and be a family man." — Guile, Street Fighter II</p>'),
	(7, 'dhalsim', 'Dhalsim', 'Street Fighter II', 'sheet|/assets/sprites/Dhalsim-sprite.png|6|168|175', '<p class="char-bio">\r\n  Dhalsim es el luchador más enigmático de Street Fighter II. Yogui hindú con poderes sobrenaturales, puede estirar sus extremidades hasta límites imposibles y escupir fuego por la boca. Lucha contra su propia naturaleza pacífica — cada combate es una contradicción entre sus creencias espirituales y la violencia necesaria para proteger a su aldea. Los cráneos que lleva al cuello pertenecen a niños de su pueblo fallecidos. Tras cada torneo, dona sus ganancias a los pobres.\r\n</p>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat"><div class="char-stat-label">Origen</div><div class="char-stat-value">India</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Estilo</div><div class="char-stat-value">Yoga</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Habilidad</div><div class="char-stat-value">Estirar cuerpo</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Motivación</div><div class="char-stat-value">Salvar su aldea</div></div>\r\n</div>\r\n\r\n<p class="char-section-title">STREET FIGHTER II</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🔥</div>\r\n    <div>\r\n      <div class="char-move-name">Yoga Fire</div>\r\n      <div class="char-move-input">↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Bola de fuego lanzada desde la boca. Lenta pero con gran hitbox — ideal para controlar el espacio y forzar saltos del rival.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🔥</div>\r\n    <div>\r\n      <div class="char-move-name">Yoga Flame</div>\r\n      <div class="char-move-input">↓↙← + Puño</div>\r\n      <p class="char-move-desc">Llamarada a quemarropa que envuelve al rival. Golpe cuerpo a cuerpo devastador — sorprendente en un personaje de largo alcance.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🌀</div>\r\n    <div>\r\n      <div class="char-move-name">Yoga Teleport</div>\r\n      <div class="char-move-input">↓↘→ o ↓↙← + 3 Puños o Patadas</div>\r\n      <p class="char-move-desc">Desaparece y reaparece en otro punto de la pantalla. Herramienta clave para confundir al rival y reposicionarse instantáneamente.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-section-title">OTROS TÍTULOS</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Yoga Inferno</div>\r\n      <div class="char-move-input">↓↘→↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Llamarada masiva que ocupa media pantalla. Versión extrema del Yoga Flame — inescapable a distancia corta y media.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Yoga Tempest</div>\r\n      <div class="char-move-input">↓↘→↓↘→ + Patada</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Torbellino de fuego que envuelve completamente al rival. El movimiento más poderoso del arsenal de Dhalsim.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-quote">"Yoga... es el camino hacia la iluminación. Tú aún no lo entiendes." — Dhalsim</p>'),
	(8, 'sagat', 'Sagat', 'Street Fighter II', 'sheet|/assets/sprites/Sagat-sprite.png|4|111|175', '<p class="char-bio">\r\n  Sagat es el emperador del Muay Thai y uno de los luchadores más temidos del mundo. Antiguo campeón mundial de artes marciales, perdió su ojo derecho y se ganó la cicatriz del pecho en una batalla legendaria contra <em>Ryu</em> — una derrota que lo marcó de por vida y lo convirtió en un hombre obsesionado con la revancha. Alto, brutal y con un alcance devastador, su estilo combina la potencia del Muay Thai tradicional con proyectiles de energía propios. Trabaja para <em>Shadaloo</em>, aunque su lealtad siempre ha sido con su propio orgullo herido.\r\n</p>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat"><div class="char-stat-label">Origen</div><div class="char-stat-value">Tailandia</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Estilo</div><div class="char-stat-value">Muay Thai</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Altura</div><div class="char-stat-value">226 cm</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Rival</div><div class="char-stat-value">Ryu</div></div>\r\n</div>\r\n\r\n<p class="char-section-title">STREET FIGHTER II</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🔥</div>\r\n    <div>\r\n      <div class="char-move-name">Tiger Shot</div>\r\n      <div class="char-move-input">↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Proyectil de energía lanzado con ambas manos. Alto o bajo según el puño usado — obliga al rival a adivinar y gestionar el espacio constantemente.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🥊</div>\r\n    <div>\r\n      <div class="char-move-name">Tiger Uppercut</div>\r\n      <div class="char-move-input">→↓↘ + Puño</div>\r\n      <p class="char-move-desc">Uppercut brutal con la rodilla elevada. La respuesta de Sagat al Shoryuken de Ryu — más lento pero con mayor daño y alcance vertical.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🦵</div>\r\n    <div>\r\n      <div class="char-move-name">Tiger Knee Crush</div>\r\n      <div class="char-move-input">↓↙←↙↓↘→ + Patada</div>\r\n      <p class="char-move-desc">Rodillazo ascendente que cruza la pantalla en diagonal. Golpe sorpresivo y difícil de bloquear que cierra la distancia en un instante.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-section-title">OTROS TÍTULOS</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Tiger Cannon</div>\r\n      <div class="char-move-input">↓↘→↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Tiger Shot masivo que atraviesa toda la pantalla. Imparable a larga distancia y con daño devastador contra cualquier rival.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Tiger Genocide</div>\r\n      <div class="char-move-input">↓↘→↓↘→ + Patada</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Tiger Knee encadenado con Tiger Uppercut. La combinación más brutal de Sagat — sube al rival al cielo con una rodilla y lo remata en el aire.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-quote">"La cicatriz que me dejaste, Ryu... un día te la devolveré." — Sagat</p>'),
	(9, 'zangief', 'Zangief', 'Street Fighter II', 'sheet|/assets/sprites/Zangief-sprite.png|4|188|175', '<p class="char-bio">\r\n  Zangief es el luchador más poderoso de Rusia y un símbolo nacional de su país. Conocido como el <em>Hombre Rojo</em>, su cuerpo es una fortaleza viviente forjada en las estepas siberianas luchando contra osos salvajes — las cicatrices que cubren su torso son prueba de ello. No lucha por dinero ni por venganza: lucha por el orgullo de su nación. Su estilo de lucha libre rusa es devastador en distancia corta — si Zangief te agarra, la pelea ha terminado.\r\n</p>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat"><div class="char-stat-label">Origen</div><div class="char-stat-value">Rusia</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Estilo</div><div class="char-stat-value">Lucha libre rusa</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Apodo</div><div class="char-stat-value">Hombre Rojo</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Motivación</div><div class="char-stat-value">Gloria de Rusia</div></div>\r\n</div>\r\n\r\n<p class="char-section-title">STREET FIGHTER II</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🌀</div>\r\n    <div>\r\n      <div class="char-move-name">Spinning Piledriver</div>\r\n      <div class="char-move-input">360° + Puño</div>\r\n      <p class="char-move-desc">Agarre giratorio que remata con un piledriver devastador. El movimiento más temido del juego — si conecta, quita casi un tercio de la barra de vida.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🌀</div>\r\n    <div>\r\n      <div class="char-move-name">Double Lariat</div>\r\n      <div class="char-move-input">3 Puños simultáneos</div>\r\n      <p class="char-move-desc">Giro con los brazos extendidos que golpea a ambos lados. Destruye proyectiles y es invencible en los primeros fotogramas — la respuesta de Zangief al Hadouken.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🥊</div>\r\n    <div>\r\n      <div class="char-move-name">Banishing Flat</div>\r\n      <div class="char-move-input">↓↘→ + Puño</div>\r\n      <p class="char-move-desc">Golpe de puño cargado de energía que destruye proyectiles al contacto. Permite a Zangief avanzar sin miedo ante luchadores de largo alcance.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-section-title">OTROS TÍTULOS</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Final Atomic Buster</div>\r\n      <div class="char-move-input">720° + Puño</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Versión extrema del Spinning Piledriver — Zangief agarra al rival, lo lanza al aire y lo remata con una serie de golpes antes del impacto final.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Siberian Blizzard</div>\r\n      <div class="char-move-input">720° + Patada</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Agarre aéreo que convierte a Zangief en un torbellino humano. Devastador contra rivales que intentan escapar por el aire.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-quote">"¡Por la madre Rusia! ¡Nadie puede vencer al Hombre Rojo!" — Zangief</p>'),
	(10, 'mr-bison', 'Mr Bison', 'Street Fighter II', 'sheet|/assets/sprites/Bison-sprite.png|3|210|175', '<p class="char-bio">\r\n  M. Bison es el villano absoluto de Street Fighter II y el líder de <em>Shadaloo</em>, una organización criminal que controla el tráfico de armas, drogas y experimentos genéticos a escala mundial. Su poder proviene del <em>Psycho Power</em>, una energía oscura que amplifica la maldad pura del alma humana. Bison no lucha por honor ni por gloria — lucha para demostrar que es un dios. Fríamente calculador y brutalmente poderoso, es el responsable de la muerte de Charlie Nash y de los experimentos sobre Cammy. El torneo Street Fighter no es para él más que un juego de entretenimiento.\r\n</p>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat"><div class="char-stat-label">Origen</div><div class="char-stat-value">Desconocido</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Organización</div><div class="char-stat-value">Shadaloo</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Poder</div><div class="char-stat-value">Psycho Power</div></div>\r\n  <div class="char-stat"><div class="char-stat-label">Objetivo</div><div class="char-stat-value">Dominio mundial</div></div>\r\n</div>\r\n\r\n<p class="char-section-title">STREET FIGHTER II</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-icon">⚡</div>\r\n    <div>\r\n      <div class="char-move-name">Psycho Crusher</div>\r\n      <div class="char-move-input">← carga → + Puño</div>\r\n      <p class="char-move-desc">Se lanza hacia el rival envuelto en energía Psycho Power girando como un torpedo. Cubre toda la pantalla y es devastador como golpe de apertura o punish.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🥊</div>\r\n    <div>\r\n      <div class="char-move-name">Double Knee Press</div>\r\n      <div class="char-move-input">← carga → + Patada</div>\r\n      <p class="char-move-desc">Dos rodillazos consecutivos que cruzan la pantalla a gran velocidad. Golpe base de su ofensiva — rápido, difícil de reaccionar y con gran alcance horizontal.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🦵</div>\r\n    <div>\r\n      <div class="char-move-name">Head Press</div>\r\n      <div class="char-move-input">↓ carga ↑ + Patada</div>\r\n      <p class="char-move-desc">Salta y aterriza con los pies sobre la cabeza del rival. Puede encadenarse con un puñetazo al suelo — uno de los movimientos más humillantes del juego.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-icon">🌀</div>\r\n    <div>\r\n      <div class="char-move-name">Scissor Kick</div>\r\n      <div class="char-move-input">← carga → + Patada</div>\r\n      <p class="char-move-desc">Patada en tijera que avanza horizontalmente. Versión de corto alcance pero más rápida que el Double Knee — ideal para presionar al rival en el rincón.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-section-title">OTROS TÍTULOS</p>\r\n<div class="char-moves-grid">\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Knee Press Nightmare</div>\r\n      <div class="char-move-input">← carga →← → + Patada</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Serie encadenada de Scissor Kicks que cruzan la pantalla múltiples veces. Imparable si el rival no bloquea el primer golpe.</p>\r\n    </div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-icon">★</div>\r\n    <div>\r\n      <div class="char-move-name">Psycho Cannon</div>\r\n      <div class="char-move-input">← carga →← → + Puño</div>\r\n      <p class="char-move-desc">Super Art (SF Alpha). Proyectil masivo de Psycho Power que ocupa toda la pantalla. La manifestación máxima del poder de Bison — lento pero absolutamente devastador.</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<p class="char-quote">"¿Para mí? Fue el martes." — M. Bison, Street Fighter</p>'),
	(11, 'cody', 'Cody', 'Final Fight', 'sheet|/assets/sprites/cody-sheet.png|2|126|175', '<div class="char-bio">\r\n  <p>Cody Travers es el héroe más accesible de Final Fight y, probablemente, el personaje con la historia más trágica de todo el universo Capcom. En 1989 era un luchador callejero con un talento natural extraordinario, novio de Jessica —hija del alcalde Haggar— y uno de los tres hombres que salvaron Metro City de la banda Mad Gear. Un héroe en toda regla.</p>\r\n  <p>Lo que vino después es otra historia. Años después de los eventos de Final Fight, Cody fue encarcelado. Los motivos exactos nunca se explican del todo, pero el patrón es claro: un hombre que vive para pelear, que no sabe hacer otra cosa, que terminó buscando problemas donde no los había. Cuando aparece en <strong>Street Fighter Alpha 3</strong>, pelea con los puños metidos en esposas. No porque no pueda quitárselas. Sino porque pelea mejor así.</p>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EN EL JUEGO</h3>\r\n<div class="char-bio">\r\n  <p>Cody es el personaje recomendado para quien empieza en Final Fight. No porque sea aburrido, sino porque su equilibrio entre velocidad y potencia le da margen de error que Haggar no tiene y la velocidad de Guy no necesita. Su combo básico de tres golpes es el más fácil de ejecutar y su uppercut —el <strong>Criminal Upper</strong>— es devastador.</p>\r\n  <p>Puede usar armas mejor que cualquier otro personaje: cuando Cody recoge un cuchillo o un tubo de hierro, hace más daño y durante más tiempo que Haggar o Guy con la misma arma. Es un detalle pequeño que dice mucho del diseño del personaje: un tipo que ha pasado su vida en la calle sabe exactamente cómo usar lo que encuentra en ella.</p>\r\n</div>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">VELOCIDAD</div>\r\n    <div class="char-stat-val">★★★★☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">POTENCIA</div>\r\n    <div class="char-stat-val">★★★★☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">ALCANCE</div>\r\n    <div class="char-stat-val">★★★☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">DIFICULTAD</div>\r\n    <div class="char-stat-val">★★☆☆☆</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MOVIMIENTOS</h3>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-name">CRIMINAL UPPER</div>\r\n    <div class="char-move-input">↓ ↘ → + Puño</div>\r\n    <div class="char-move-desc">Su uppercut característico. Lanza al enemigo por los aires. Golpe antiaéreo y para romper guardias.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">TORNADO SWEEP</div>\r\n    <div class="char-move-input">→ ↓ ↘ + Patada</div>\r\n    <div class="char-move-desc">Patada giratoria al nivel del suelo. Barre a los enemigos que le rodean.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">KNIFE THROW</div>\r\n    <div class="char-move-input">Con cuchillo: → + Puño</div>\r\n    <div class="char-move-desc">Lanza el cuchillo a distancia. Uno de los ataques a distancia más efectivos del juego.</div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-name">FINAL FIGHT COMBO</div>\r\n    <div class="char-move-input">Puño × 3</div>\r\n    <div class="char-move-desc">Su combo estándar. Tres golpes rápidos con remate que hace retroceder al enemigo. El combo más fácil de ejecutar del juego.</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MÁS ALLÁ DE METRO CITY</h3>\r\n<div class="char-bio">\r\n  <p>Cody reaparece en <strong>Street Fighter Alpha 3</strong> (1998) como personaje jugable, pero ya no es el héroe de 1989. Es un preso con esposas que ha escapado de la cárcel no para recuperar su vida sino porque en la calle puede seguir peleando. Su nivel de pelea ha aumentado —domina el Bushinryu que le enseñó Guy— pero su espíritu está roto.</p>\r\n  <p>En <strong>Street Fighter V</strong> (2016) completa su arco: sale de la cárcel, se convierte en alcalde de Metro City —el mismo cargo que tenía Haggar— y vuelve a ser, a su manera torturada, alguien que protege a los demás. El luchador callejero que salvó la ciudad termina gobernándola. No está mal para alguien que peleaba con esposas puestas.</p>\r\n</div>'),
	(13, 'guy', 'Guy', 'Final Fight', 'sheet|/assets/sprites/Guy-sprite.png|6|84|175', '<div class="char-bio">\r\n  <p>Guy es el personaje más enigmático de los tres héroes de Final Fight y el único con un código de honor explícito. Maestro del <strong>Bushin-ryu</strong>, el antiguo estilo de ninjutsu que lleva siglos transmitiéndose de maestro a discípulo, Guy no pelea por venganza ni por amor —aunque Jessica sea amiga suya— sino porque proteger Metro City es lo que haría cualquier seguidor del Bushin. Es su deber. No hay más explicación necesaria.</p>\r\n  <p>Su maestro <strong>Zeku</strong> le transfirió el título de 39º sucesor del Bushin-ryu antes de los eventos de Final Fight, desapareciendo después sin dejar rastro. Guy pasará años intentando encontrarle. Mientras tanto, sigue haciendo lo que sabe: moverse más rápido que cualquier enemigo, golpear en los puntos exactos, y desaparecer antes de que nadie le vea llegar.</p>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EN EL JUEGO</h3>\r\n<div class="char-bio">\r\n  <p>Guy es el personaje de mayor dificultad de Final Fight y el más gratificante cuando lo dominas. Su velocidad de movimiento es máxima —cruza la pantalla en un instante— pero sus golpes individuales hacen menos daño que los de Cody o Haggar. La clave está en no parar: Guy está diseñado para encadenar, para no dejar respirar al enemigo, para moverse antes de que te rodeen. Si te quedas quieto, pierdes su ventaja principal.</p>\r\n  <p>Su combo básico termina con una patada ascendente que lanza al enemigo hacia arriba, perfecta para encadenar con un agarre en el aire. Es el personaje que mejor aprovecha la verticalidad del sistema de combate. No es el recomendado para empezar —eso es Cody— pero el jugador que domina a Guy rara vez quiere volver a los otros dos.</p>\r\n</div>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">VELOCIDAD</div>\r\n    <div class="char-stat-val">★★★★★</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">POTENCIA</div>\r\n    <div class="char-stat-val">★★★☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">ALCANCE</div>\r\n    <div class="char-stat-val">★★★☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">DIFICULTAD</div>\r\n    <div class="char-stat-val">★★★★☆</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MOVIMIENTOS</h3>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-name">BUSHIN SENPUKYAKU</div>\r\n    <div class="char-move-input">↓ ↘ → + Patada</div>\r\n    <div class="char-move-desc">Patada giratoria en salto que golpea a varios enemigos a la vez. Su movimiento más icónico y el mejor para salir de situaciones comprometidas.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">BUSHIN IZUNA OTOSHI</div>\r\n    <div class="char-move-input">Salto + agarre en el aire</div>\r\n    <div class="char-move-desc">Agarra al enemigo en pleno vuelo y lo estampa contra el suelo. Devastador y humillante en igual medida.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">BUSHIN HASSOUKYAKU</div>\r\n    <div class="char-move-input">→ → + Patada</div>\r\n    <div class="char-move-desc">Carrera seguida de una serie de patadas rápidas. La forma más efectiva de cruzar la pantalla y entrar en grupo.</div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-name">COMBO BUSHIN</div>\r\n    <div class="char-move-input">Puño × 3</div>\r\n    <div class="char-move-desc">Tres golpes veloces con remate de patada ascendente. Menor daño por golpe que Cody, pero se ejecuta más rápido y encadena mejor con agarres.</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MÁS ALLÁ DE METRO CITY</h3>\r\n<div class="char-bio">\r\n  <p>Guy reaparece en <strong>Street Fighter Alpha</strong> (1995) como uno de los personajes principales de la saga. Aquí no es un héroe que celebra su victoria de 1989 —es un ninja que busca a su maestro desaparecido e investiga la creciente influencia de <strong>Shadaloo</strong>. Su presencia en Alpha lo convierte en uno de los personajes con mayor continuidad narrativa del universo Capcom, conectando Final Fight con Street Fighter de forma que ningún otro personaje logra.</p>\r\n  <p>En <strong>Super Street Fighter IV</strong> (2010) regresa como personaje jugable con su moveset más completo hasta la fecha. Zeku por fin tiene un arco cerrado, el Bushin-ryu tiene sucesor confirmado, y Guy tiene paz. O algo parecido. Porque un ninja que ha pasado veinte años buscando pelea difícilmente sabe qué hacer cuando ya no tiene ninguna pendiente.</p>\r\n</div>'),
	(14, 'haggar', 'Haggar', 'Final Fight', 'sheet|/assets/sprites/Haggar-sprite.png|11|161|175', '<div class="char-bio">\r\n  <p>Mike Haggar no es un político al uso. Antes de ser alcalde de Metro City era luchador profesional —uno de los mejores de su generación— y cuando la banda <strong>Mad Gear</strong> secuestró a su hija <strong>Jessica</strong>, no llamó a la policía. Se subió las tirantes, se puso los guantes y salió a la calle a recuperarla él mismo. Doscientos treinta kilos de músculo con un bigote que da más miedo que cualquier arma. Así de sencillo.</p>\r\n  <p>Haggar representa algo que el videojuego de los ochenta entendía perfectamente y que se ha perdido casi por completo: el héroe sin matices. No tiene trauma oculto, no tiene arco de redención, no tiene dilema moral. Alguien tiene a su hija. Él va a por ella. Lo que ocurra en el camino es problema de quien se interponga.</p>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EN EL JUEGO</h3>\r\n<div class="char-bio">\r\n  <p>Haggar es el personaje más lento de Final Fight y el más poderoso con diferencia. Cada golpe suyo hace temblar la pantalla. Su combo básico tiene menos hits que el de Cody o Guy, pero el daño por impacto es tan superior que la diferencia se nivela rápido. El problema es llegar al enemigo: Haggar necesita espacio y tiempo para colocarse, y en las fases avanzadas —cuando la pantalla se llena de Mad Gears— ese tiempo no siempre está disponible.</p>\r\n  <p>Donde Haggar es absolutamente imbatible es en el agarre. Cuando pone las manos encima de un enemigo, ese enemigo ya ha perdido. Su <strong>Spinning Pile Driver</strong> hace el daño más alto de cualquier agarre del juego, y lanzar a un enemigo contra otro es el movimiento más eficiente —y satisfactorio— de todo Final Fight. No es el personaje recomendado para empezar, pero quien lo domina aprende a leer la pantalla de una forma que los otros dos no enseñan.</p>\r\n</div>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">VELOCIDAD</div>\r\n    <div class="char-stat-val">★★☆☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">POTENCIA</div>\r\n    <div class="char-stat-val">★★★★★</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">ALCANCE</div>\r\n    <div class="char-stat-val">★★★★☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">DIFICULTAD</div>\r\n    <div class="char-stat-val">★★★☆☆</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MOVIMIENTOS</h3>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-name">SPINNING PILE DRIVER</div>\r\n    <div class="char-move-input">Agarre + rotación</div>\r\n    <div class="char-move-desc">El movimiento definitorio de Haggar. Agarra al enemigo, gira como un trompo y lo clava contra el suelo de cabeza. El golpe de agarre con más daño del juego.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">DOUBLE LARIAT</div>\r\n    <div class="char-move-input">↓ ↘ → + Puño</div>\r\n    <div class="char-move-desc">Giro con los brazos extendidos que golpea a todos los enemigos alrededor. Ideal para salir de situaciones de encierro. Consume energía.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">BODY SLAM</div>\r\n    <div class="char-move-input">Agarre + dirección</div>\r\n    <div class="char-move-desc">Lanza al enemigo agarrado contra el suelo o contra otro enemigo. Usado bien, puede encadenar daño en cascada sobre grupos.</div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-name">COMBO HAGGAR</div>\r\n    <div class="char-move-input">Puño × 2 + agarre</div>\r\n    <div class="char-move-desc">Dos puñetazos lentos pero brutales seguidos de agarre automático. Menos hits que Cody o Guy, más daño total por secuencia. Sin discusión.</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MÁS ALLÁ DE METRO CITY</h3>\r\n<div class="char-bio">\r\n  <p>Haggar protagoniza <strong>Final Fight 2</strong> (1993) y <strong>Final Fight 3</strong> (1995) en SNES, continuando su cruzada contra el crimen organizado con distintos compañeros. Es el único personaje que aparece en las tres entregas principales de la saga, lo que lo convierte en la columna vertebral de la franquicia. Metro City sin Haggar es simplemente otra ciudad. Con él es un campo de batalla con alcalde.</p>\r\n  <p>Su momento más inesperado llega en <strong>Marvel vs. Capcom 3</strong> (2011), donde Haggar aparece como personaje jugable y resulta ser exactamente lo que promete: un luchador enorme, lento, devastador, que lanza a los enemigos contra el suelo en una pantalla llena de superhéroes y villanos cósmicos sin que nadie le parezca fuera de lugar. Porque Haggar nunca está fuera de lugar. Es Haggar.</p>\r\n</div>'),
	(16, 'pac-man', 'Pac-Man', 'Pac-Man', 'sheet|/assets/sprites/Pac_man-sprite.png|3|177|175', '<div class="char-bio">\r\n  <p>Pac-Man no tiene historia de origen. No tiene motivación, no tiene enemigos con los que tenga una rivalidad personal, no tiene un pasado traumático que lo empuje a actuar. Es una boca amarilla en un laberinto. Y aun así, en 1980, se convirtió en el personaje más reconocible del planeta. <strong>Antes que Mario. Antes que cualquiera.</strong></p>\r\n  <p>Su creador, <strong>Toru Iwatani</strong>, quería un personaje que no intimidara, que no fuera agresivo, que pudiera gustarle a cualquiera —incluyendo a las mujeres y a la gente que nunca había tocado una máquina arcade. Lo consiguió. Pac-Man fue el primer personaje de videojuego en tener cara reconocible, en aparecer en camisetas, en protagonizar una serie de animación, en convertirse en icono cultural antes de que eso fuera algo que los videojuegos pudieran hacer.</p>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EN EL JUEGO</h3>\r\n<div class="char-bio">\r\n  <p>Pac-Man se mueve por el laberinto en cuatro direcciones. Sin saltar, sin correr, sin habilidades especiales. Solo caminar, comer puntos y sobrevivir. La gracia está en que con esas limitaciones el juego genera situaciones de tensión, decisión y satisfacción que títulos mucho más complejos no consiguen igualar.</p>\r\n  <p>Su único momento de poder son las <strong>Power Pellets</strong> — los cuatro puntos grandes de las esquinas. Durante unos segundos la dinámica se invierte: los fantasmas huyen y Pac-Man caza. Es el instante más satisfactorio del juego, y lleva cuarenta años siéndolo.</p>\r\n</div>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">VELOCIDAD</div>\r\n    <div class="char-stat-val">★★★☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">POTENCIA</div>\r\n    <div class="char-stat-val">★☆☆☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">CON POWER PELLET</div>\r\n    <div class="char-stat-val">★★★★★</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">DIFICULTAD</div>\r\n    <div class="char-stat-val">★★☆☆☆</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MÁS ALLÁ DEL LABERINTO</h3>\r\n<div class="char-bio">\r\n  <p>Pac-Man apareció en más de treinta juegos entre 1980 y 1990. <strong>Ms. Pac-Man</strong> (1982) mejoró la fórmula con laberintos más variados y movimiento más impredecible de los fantasmas —muchos consideran que es mejor juego que el original. <strong>Pac-Land</strong> (1984) lo convirtió en plataformas. <strong>Pac-Mania</strong> (1987) añadió perspectiva isométrica y la posibilidad de saltar sobre los fantasmas.</p>\r\n  <p>En <strong>Super Smash Bros.</strong> (2014) llegó su consagración definitiva como icono de la cultura del videojuego, peleando junto a Mario, Link y Donkey Kong como si siempre hubiera estado ahí. Porque en cierto modo, siempre estuvo.</p>\r\n</div>'),
	(18, 'jack-tenrec', 'Jack Tenrec', 'Cadillacs and Dinosaurs', 'sheet|/assets/sprites/Jack-sprite.png|2|123|175', '<div class="char-bio">\r\n  <p>Jack Tenrec es mecánico, ecologista y el hombre más peligroso del siglo XXVI. En un mundo donde los dinosaurios han vuelto a dominar la Tierra y la civilización tal como la conocíamos ha desaparecido, Jack conduce Cadillacs de los años 50, repara motores y reparte puñetazos con la misma eficiencia.</p>\r\n  <p>No es un héroe al uso. Es un hombre de principios férreos en un mundo sin reglas: respeta a los dinosaurios, odia a quien contamina y no duda en partirle la cara a quien se lo merece. Su compañera Hannah Dundee lo define perfectamente: <em>"Mitad hombre, mitad máquina, mitad dinosaurio."</em> Las matemáticas no cuadran, pero el concepto sí.</p>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EN EL JUEGO</h3>\r\n<div class="char-bio">\r\n  <p>Jack es el personaje más equilibrado de los cuatro disponibles. Ni el más rápido ni el más fuerte, pero el más completo: alcance decente, recuperación rápida y una versatilidad que lo convierte en la elección natural para quien quiere dominar todos los niveles sin depender de una sola estrategia.</p>\r\n  <p>Su gran ventaja diferencial es el uso de armas. Jack saca más partido que cualquier otro personaje a los objetos del escenario: pistolas, lanzacohetes, tuberías. Un mecánico acostumbrado a improvisar con lo que tiene a mano. En cooperativo es el líder natural del grupo.</p>\r\n</div>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">VELOCIDAD</div>\r\n    <div class="char-stat-val">★★★★☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">POTENCIA</div>\r\n    <div class="char-stat-val">★★★★☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">ALCANCE</div>\r\n    <div class="char-stat-val">★★★☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">DIFICULTAD</div>\r\n    <div class="char-stat-val">★★☆☆☆</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MOVIMIENTOS</h3>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-name">PUÑETAZO DIRECTO</div>\r\n    <div class="char-move-input">Botón de ataque</div>\r\n    <div class="char-move-desc">Golpe rápido con buena recuperación. El pan de cada día. Encadena hasta tres veces para el combo básico.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">PATADA GIRATORIA</div>\r\n    <div class="char-move-input">Salto + Ataque</div>\r\n    <div class="char-move-desc">Útil para limpiar grupos de enemigos a ambos lados. Gran área de impacto.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">LLAVE AL SUELO</div>\r\n    <div class="char-move-input">Agarre + Ataque</div>\r\n    <div class="char-move-desc">Agarra al enemigo y lo estampa contra el suelo. Daño alto, requiere distancia corta.</div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-name">ATAQUE CON ARMA</div>\r\n    <div class="char-move-input">Recoger objeto + Ataque</div>\r\n    <div class="char-move-desc">Jack es especialmente eficiente con objetos del escenario. Lanzacohetes, pistolas y palos hacen más daño en sus manos que en las del resto del equipo.</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EL TRUCO DE LOS DINOSAURIOS</h3>\r\n<div class="char-bio">\r\n  <p>Lo que separa a un jugador corriente de uno bueno en Cadillacs and Dinosaurs no es la velocidad ni la potencia: es saber usar los dinosaurios. Jack, como protagonista del juego, está diseñado para aprovechar este mecánica mejor que nadie.</p>\r\n  <p>Cuando aparece un dinosaurio en pantalla, no lo evites. <strong>Atrae a los enemigos hacia él.</strong> Un T-Rex hace en dos segundos lo que a ti te costaría medio crédito. Es la diferencia entre terminar el nivel con vidas de sobra o insertar otra moneda.</p>\r\n  <blockquote>El jugador inteligente no es el que más pega. Es el que consigue que un T-Rex haga el trabajo por él.</blockquote>\r\n</div>'),
	(20, 'hannah-dundee', 'Hannah Dundee', 'Cadillacs and Dinosaurs', 'sheet|/assets/sprites/Hanna-sprite.png|5|112|175', '<div class="char-bio">\r\n  <p>Hannah Dundee es diplomática, embajadora de Wasoon y probablemente la persona más inteligente de todas las que aparecen en Cadillacs and Dinosaurs. En un mundo post-apocalíptico donde la mayoría de la gente resuelve los problemas a puñetazos, Hannah prefiere negociar. Cuando la negociación falla —y en los recreativos siempre falla— demuestra que también sabe repartir.</p>\r\n  <p>Su relación con Jack Tenrec es complicada: él es un hombre de acción que no piensa demasiado, ella es una mujer de ideas que piensa demasiado. Se complementan a la perfección y se sacan de quicio con la misma facilidad. En el cómic original de Mark Schultz su química es el motor de toda la historia. En el recreativo simplemente se ponen a golpear juntos a los malos, que también está bien.</p>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EN EL JUEGO</h3>\r\n<div class="char-bio">\r\n  <p>Hannah es el personaje más rápido de los cuatro. Lo que pierde en potencia bruta lo gana en velocidad de ataque y movilidad: sus combos se ejecutan antes, su recuperación es más rápida y puede esquivar situaciones comprometidas que a Mustapha o Mess les costarían una vida.</p>\r\n  <p>Es la elección natural para el jugador con experiencia que ya conoce los niveles y quiere maximizar la eficiencia. En cooperativo encaja perfectamente junto a Jack: él absorbe el daño y ella limpia los flancos antes de que nadie reaccione.</p>\r\n</div>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">VELOCIDAD</div>\r\n    <div class="char-stat-val">★★★★★</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">POTENCIA</div>\r\n    <div class="char-stat-val">★★★☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">ALCANCE</div>\r\n    <div class="char-stat-val">★★★☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">DIFICULTAD</div>\r\n    <div class="char-stat-val">★★★☆☆</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MOVIMIENTOS</h3>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-name">COMBO RÁPIDO</div>\r\n    <div class="char-move-input">Botón de ataque × 3</div>\r\n    <div class="char-move-desc">Tres golpes encadenados más rápidos que los de cualquier otro personaje. Ideal para interrumpir ataques enemigos.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">PATADA LATERAL</div>\r\n    <div class="char-move-input">Salto + Ataque</div>\r\n    <div class="char-move-desc">Patada en el aire con gran precisión. Hannah aprovecha su agilidad para atacar desde ángulos que otros personajes no pueden alcanzar.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">BARRIDO BAJO</div>\r\n    <div class="char-move-input">Agarre + Dirección</div>\r\n    <div class="char-move-desc">Derriba al enemigo de una sola zancada. Útil para romper el ritmo cuando te rodean varios a la vez.</div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-name">CONTRAATAQUE</div>\r\n    <div class="char-move-input">Justo antes de recibir golpe</div>\r\n    <div class="char-move-desc">La velocidad de Hannah le permite reaccionar antes que el resto. Con práctica, puede convertir cualquier ataque enemigo en una oportunidad de contragolpe.</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MÁS ALLÁ DEL RECREATIVO</h3>\r\n<div class="char-bio">\r\n  <p>Hannah Dundee viene del cómic <strong>Xenozoic Tales</strong> de Mark Schultz, publicado desde 1987. En el original es un personaje mucho más desarrollado que en el recreativo: diplomática brillante, experta en dinosaurios y el verdadero cerebro detrás de las operaciones que Jack ejecuta a puñetazos.</p>\r\n  <p>Capcom la trasladó al juego respetando su esencia —ágil, inteligente, capaz— pero reduciendo su rol al de personaje jugable dentro del beat \'em up. No importa: en los recreativos españoles de 1992, Hannah Dundee era la elección de quien quería demostrar que sabía jugar de verdad.</p>\r\n  <blockquote>Mientras los demás pegaban más fuerte, Hannah ya había terminado el combo.</blockquote>\r\n</div>'),
	(22, 'mustapha-cairo', 'Mustapha Cairo', 'Cadillacs and Dinosaurs', 'sheet|/assets/sprites/Mustapha-sprite.png|3|120|175', '<div class="char-bio">\r\n  <p>Mustapha Cairo es el músculo del grupo. En un mundo donde la fuerza bruta sigue siendo la moneda más valiosa, Mustapha es millonario. Cazador, superviviente y hombre de pocas palabras, lleva años moviéndose por los territorios más peligrosos del siglo XXVI con la misma calma con la que otros se toman un café.</p>\r\n  <p>No es el más rápido ni el más listo del equipo. No necesita serlo. Cuando Mustapha llega a un sitio, los problemas se resuelven solos. O se resuelven a puñetazos, que en el fondo es lo mismo.</p>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EN EL JUEGO</h3>\r\n<div class="char-bio">\r\n  <p>Mustapha es el personaje de mayor potencia de los cuatro. Cada golpe suyo hace más daño que el equivalente de Jack o Hannah, y su resistencia le permite aguantar situaciones que a los otros personajes les costarían una vida. El precio a pagar es la velocidad: sus combos tardan más en ejecutarse y su recuperación entre golpes es la más lenta del grupo.</p>\r\n  <p>Es la elección para quien quiere arrasar sin complicaciones. No requiere precisión ni timing especial — solo saber cuándo golpear y confiar en que el golpe va a doler. En cooperativo es el tanque natural: va delante, absorbe el daño y deja el trabajo fino para Hannah o Jack.</p>\r\n</div>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">VELOCIDAD</div>\r\n    <div class="char-stat-val">★★☆☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">POTENCIA</div>\r\n    <div class="char-stat-val">★★★★★</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">ALCANCE</div>\r\n    <div class="char-stat-val">★★★★☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">DIFICULTAD</div>\r\n    <div class="char-stat-val">★★☆☆☆</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MOVIMIENTOS</h3>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-name">GOLPE DEMOLEDOR</div>\r\n    <div class="char-move-input">Botón de ataque</div>\r\n    <div class="char-move-desc">Un puñetazo directo con el doble de daño que el equivalente de cualquier otro personaje. Lento, pero cuando conecta, conecta.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">PLANCHA AÉREA</div>\r\n    <div class="char-move-input">Salto + Ataque</div>\r\n    <div class="char-move-desc">Se lanza en horizontal aplastando todo lo que pille por delante. Gran área de impacto, difícil de esquivar para los enemigos.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">LANZAMIENTO</div>\r\n    <div class="char-move-input">Agarre + Dirección</div>\r\n    <div class="char-move-desc">Coge al enemigo y lo lanza contra los demás. En grupos numerosos es el movimiento más eficiente del juego — un enemigo se convierte en proyectil.</div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-name">COMBO DE DOS GOLPES</div>\r\n    <div class="char-move-input">Ataque × 2</div>\r\n    <div class="char-move-desc">Solo dos golpes, pero cada uno vale por tres. El segundo impacto lanza al enemigo por los aires. Simple, brutal y efectivo.</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EL HOMBRE DEL SOMBRERO</h3>\r\n<div class="char-bio">\r\n  <p>Mustapha Cairo viene del cómic <strong>Xenozoic Tales</strong> de Mark Schultz, donde es uno de los personajes secundarios más queridos. Cazador experimentado, conoce los territorios salvajes mejor que nadie y sirve de guía al grupo en más de una ocasión.</p>\r\n  <p>Capcom lo trasladó al recreativo como el arquetipo clásico del personaje lento y poderoso — el mismo rol que ocupa Haggar en Final Fight o Zangief en Street Fighter. Es el personaje que eligen los jugadores que quieren sentir que cada golpe importa, que no necesitan velocidad porque cuando dan, dan bien.</p>\r\n  <blockquote>En el salón recreativo de 1992, Mustapha era el personaje del que más se dudaba al principio y al que más se volvía al final.</blockquote>\r\n</div>'),
	(23, 'mess-o-bradovich', 'Mess O\'Bradovich', 'Cadillacs and Dinosaurs', 'sheet|/assets/sprites/Mess-sprite.png|4|99|175', '<div class="char-bio">\r\n  <p>Mess O\'Bradovich es el más grande, el más pesado y el más temible de los cuatro protagonistas de Cadillacs and Dinosaurs. No hay mucho que explicar sobre Mess: es un hombre enorme que ocupa demasiado espacio en cualquier habitación y que resuelve los problemas de la única manera que conoce. Con las manos.</p>\r\n  <p>En el cómic original de Mark Schultz es un personaje secundario entrañable — ese gigante de buen corazón que asusta a primera vista y que luego resulta ser el más leal del grupo. En el recreativo Capcom lo convirtió en lo que era inevitable: el personaje más destructivo de los cuatro.</p>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EN EL JUEGO</h3>\r\n<div class="char-bio">\r\n  <p>Mess es el extremo opuesto de Hannah: máxima potencia, mínima velocidad. Sus golpes hacen el mayor daño del juego, su resistencia es superior a la del resto y su tamaño le da un alcance natural que otros personajes no tienen. El problema es que cuando falla un golpe, la recuperación es tan lenta que los enemigos tienen tiempo de sobra para devolvérselo.</p>\r\n  <p>Es el personaje para quien quiere sentir cada impacto. No requiere técnica ni precisión — requiere paciencia y saber cuándo entrar. En cooperativo es el demoledor: va a los jefes directamente mientras el resto limpia los flancos.</p>\r\n</div>\r\n\r\n<div class="char-stats-grid">\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">VELOCIDAD</div>\r\n    <div class="char-stat-val">★☆☆☆☆</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">POTENCIA</div>\r\n    <div class="char-stat-val">★★★★★</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">ALCANCE</div>\r\n    <div class="char-stat-val">★★★★★</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">DIFICULTAD</div>\r\n    <div class="char-stat-val">★★☆☆☆</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► MOVIMIENTOS</h3>\r\n<div class="char-moves-grid">\r\n  <div class="char-move">\r\n    <div class="char-move-name">PUÑETAZO APLASTANTE</div>\r\n    <div class="char-move-input">Botón de ataque</div>\r\n    <div class="char-move-desc">El golpe más poderoso del juego. Cuando conecta, el enemigo sale volando. Cuando falla, Mess se queda expuesto durante medio segundo eterno.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">SALTO APLASTAMIENTO</div>\r\n    <div class="char-move-input">Salto + Ataque</div>\r\n    <div class="char-move-desc">Se deja caer sobre los enemigos con todo su peso. Daño en área, imposible de ignorar. Los enemigos pequeños simplemente desaparecen.</div>\r\n  </div>\r\n  <div class="char-move">\r\n    <div class="char-move-name">LANZAMIENTO BRUTAL</div>\r\n    <div class="char-move-input">Agarre + Dirección</div>\r\n    <div class="char-move-desc">Coge al enemigo con una sola mano y lo lanza al otro extremo de la pantalla. El lanzamiento más largo del juego — un enemigo puede llevarse por delante a tres más al caer.</div>\r\n  </div>\r\n  <div class="char-move super">\r\n    <div class="char-move-name">GOLPE GIRATORIO</div>\r\n    <div class="char-move-input">Ataque en movimiento</div>\r\n    <div class="char-move-desc">Gira sobre sí mismo barriendo todo lo que le rodea. Lento de ejecutar pero devastador en grupos. El movimiento que justifica elegir a Mess sobre cualquier otro personaje.</div>\r\n  </div>\r\n</div>\r\n\r\n<h3 class="char-section-title">► EL GIGANTE DEL SIGLO XXVI</h3>\r\n<div class="char-bio">\r\n  <p>Mess O\'Bradovich representa el arquetipo más puro del beat \'em up: el personaje grande y lento que recompensa la paciencia con destrucción masiva. Es el Hugo de Final Fight, el Zangief de Street Fighter, el Haggar llevado al extremo.</p>\r\n  <p>En los recreativos españoles de 1992 era el personaje que elegían los que querían impresionar. No el más fácil de dominar, no el más eficiente — pero el más espectacular cuando las cosas salían bien.</p>\r\n  <blockquote>Nadie recuerda haber visto a Mess fallar un golpe. Probablemente porque cuando fallaba, nadie sobrevivía para contarlo.</blockquote>\r\n</div>');

-- Volcando estructura para tabla myarcadezone.personaje_datos
CREATE TABLE IF NOT EXISTS `personaje_datos` (
  `id` int NOT NULL AUTO_INCREMENT,
  `personaje_id` int NOT NULL,
  `clave` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `valor` varchar(300) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `orden` tinyint NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `personaje_id` (`personaje_id`),
  CONSTRAINT `personaje_datos_ibfk_1` FOREIGN KEY (`personaje_id`) REFERENCES `personajes` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=43 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

