-- Volcando estructura para tabla myarcadezone.pinball_datos
CREATE TABLE IF NOT EXISTS `pinball_datos` (
  `id` int NOT NULL AUTO_INCREMENT,
  `juego_id` int NOT NULL,
  `clave` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `valor` text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  KEY `juego_id` (`juego_id`),
  CONSTRAINT `pinball_datos_ibfk_1` FOREIGN KEY (`juego_id`) REFERENCES `juegos` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=141 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

