	(8, 'Cadillacs and Dinosaurs', 'Cadillacs and Dinosaurs', 'Isao Abe y Syun Nishigaki', 'https://ia902805.us.archive.org/20/items/06-cadillacs-the-four-heroes-stage-1-1-ending-2/06-Cadillacs%20-The%20Four%20Heroes-%20%28Stage%201-1%2C%20Ending%202%29.mp3', 0, 1, '2026-05-01 18:11:42'),
