-- Volcando estructura para tabla myarcadezone.secciones_resena
CREATE TABLE IF NOT EXISTS `secciones_resena` (
  `id` int NOT NULL AUTO_INCREMENT,
  `juego_id` int NOT NULL,
  `orden` tinyint NOT NULL DEFAULT '0',
  `titulo_h2` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `contenido_html` mediumtext COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  KEY `juego_id` (`juego_id`),
  CONSTRAINT `secciones_resena_ibfk_1` FOREIGN KEY (`juego_id`) REFERENCES `juegos` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=54 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Volcando datos para la tabla myarcadezone.secciones_resena: ~39 rows (aproximadamente)
INSERT INTO `secciones_resena` (`id`, `juego_id`, `orden`, `titulo_h2`, `contenido_html`) VALUES
	(1, 1, 1, 'LA MÁQUINA QUE LO CAMBIÓ TODO', '<p>Febrero de 1991. En los salones recreativos de medio mundo aparece una máquina diferente. Una pantalla grande, dos mandos de seis botones, y ocho luchadores con nombres y países de origen. <strong>Street Fighter II: The World Warrior</strong> no llegó al mercado — llegó como una detonación.</p>\r\n\r\n<p>Capcom llevaba años trabajando en la fórmula. El primer Street Fighter de 1987 era prometedor pero tosco. Cuatro años de desarrollo después, Yoshiki Okamoto y su equipo entregaron algo que nadie había visto: un juego de lucha con personajes diferenciados, movimientos especiales ejecutables con precisión, y una profundidad táctica que lo hacía diferente en cada partida.</p>\r\n\r\n<div class="highlight-box"><p>En España llegó en 1991 a los salones recreativos. Recuerda la moneda de <strong>25 pesetas</strong>, el círculo de espectadores alrededor de la máquina, y ese momento de tensión cuando elegías personaje antes de que el rival viera tu elección.</p></div>\r\n\r\n<p>La máquina fue un fenómeno inmediato. Las salas recreativas que instalaban un Street Fighter II veían colas de espera. Los dueños de los salones pedían más unidades. <strong>Capcom no daba abasto.</strong> El juego recaudó más de 1.500 millones de dólares solo en recreativas — una cifra que no se había visto desde los tiempos de Pac-Man.</p>'),
	(2, 1, 2, 'EL SISTEMA DE LUCHA', '<p>Lo que hacía diferente a Street Fighter II no era solo que tuviera buenos personajes — era que cada uno jugaba de forma <strong>radicalmente distinta</strong>. Ryu y Ken eran versiones del mismo arquetipo pero con matices diferentes. Guile era un personaje de espera y contraataque. Blanka era caos puro. Zangief requería paciencia y lectura del rival.</p>\r\n\r\n<p>El sistema de seis botones — tres puñetazos y tres patadas en versión débil, media y fuerte — multiplicaba las opciones sin complicar el aprendizaje básico. Podías empezar a disfrutar el juego en tu primera partida, pero necesitabas <strong>cientos de horas</strong> para dominarlo de verdad.</p>\r\n\r\n<p>Los movimientos especiales se ejecutaban con secuencias de joystick: el Hadouken de Ryu con cuarto de círculo adelante más puño, el Shoryuken con la secuencia hacia adelante-abajo-diagonal, el Sonic Boom de Guile cargando atrás. Mecánicas que parecían simples pero que escondían una profundidad enorme en el <em>timing</em>, la distancia y la lectura del oponente.</p>\r\n\r\n<div class="highlight-box"><p>El <strong>sistema de combo</strong> nació aquí casi por accidente — los programadores descubrieron que encadenar golpes era posible por la forma en que el juego procesaba los inputs, y en vez de eliminarlo lo convirtieron en una mecánica central. Un error que se convirtió en el fundamento del género.</p></div>'),
	(3, 1, 3, 'LOS OCHO GUERREROS', '<p>Ocho personajes, ocho países, ocho filosofías de juego distintas. El roster original de Street Fighter II es uno de los diseños más influyentes de la historia de los videojuegos — cada personaje se convirtió en un arquetipo que el género repite hasta hoy.</p>\r\n\r\n<p><strong>Ryu</strong> (Japón) y <strong>Ken</strong> (EE.UU.) compartían base pero tenían personalidades distintas. <strong>Guile</strong> (EE.UU.) con su peinado imposible y su Sonic Boom de carga era el favorito de los jugadores defensivos. <strong>Chun-Li</strong> (China) era la primera gran protagonista femenina del género, rápida y técnica. <strong>Blanka</strong> (Brasil) desconcertaba a cualquier rival nuevo con sus saltos eléctricos. <strong>Dhalsim</strong> (India) redefinió el concepto de keepaway con sus extremidades elásticas. <strong>Zangief</strong> (URSS) era devastador en corto pero desesperante de acercar. <strong>E. Honda</strong> (Japón) con sus Hyakuretsuken hacía las delicias de los jugadores agresivos.</p>\r\n\r\n<p>Y luego estaban los cuatro jefes — <strong>Balrog, Vega, Sagat y M. Bison</strong> — que en la versión Champion Edition pasaron a ser jugables, desatando un debate sobre equilibrio que dura hasta hoy.</p>'),
	(4, 1, 4, 'GRÁFICOS Y BANDA SONORA', '<p>El hardware CPS-1 de Capcom permitió sprites de un tamaño y una fluidez que dejaban en evidencia a cualquier otro juego de 1991. Los personajes eran grandes, detallados, y sus animaciones de derrota — Ryu sacudiéndose el polvo, Guile levantando el puño — tenían una personalidad que los jugadores de la época nunca habían visto en un recreativo.</p>\r\n\r\n<p>Los escenarios eran postales de sus países de origen: la India de Dhalsim con elefantes en el fondo, el Hong Kong de Chun-Li con el mercado animado, las ruinas tailandesas de Sagat. Cada escenario tenía vida propia más allá del combate.</p>\r\n\r\n<p>La banda sonora compuesta por <strong>Yoko Shimomura</strong> (con contribuciones de Isao Abe) es posiblemente la más reconocible de la historia del género. El tema de Guile se convirtió en meme décadas después precisamente porque es tan bueno que <em>va con todo</em>. El tema de Ryu, de Ken, de Chun-Li — cada uno capturaba la personalidad del personaje de forma inmediata.</p>\r\n\r\n<div class="highlight-box"><p>Yoko Shimomura compuso la mayor parte de la banda sonora de Street Fighter II antes de irse a Square, donde compondría la música de <strong>Kingdom Hearts</strong> y otros títulos legendarios. Street Fighter II fue su carta de presentación al mundo.</p></div>'),
	(5, 1, 5, 'EL IMPACTO: ANTES Y DESPUÉS', '<p>Es difícil exagerar el impacto de Street Fighter II en la industria. Antes de 1991 existían juegos de lucha — el propio Street Fighter, Karate Champ, International Karate. Después de Street Fighter II, <strong>todos los géneros miraban hacia él</strong>.</p>\r\n\r\n<p>SNK respondió con Fatal Fury y la saga King of Fighters. Midway con Mortal Kombat. Sega con Virtua Fighter. Williams con Killer Instinct. Todos bebían del modelo que Capcom había establecido: roster de personajes diferenciados, movimientos especiales, barra de vida, combates por rounds.</p>\r\n\r\n<p>La versión de <strong>Super Nintendo</strong> en 1992 vendió más de 6,3 millones de copias y es considerada una de las mejores conversiones domésticas de un arcade de su época. Demostraba que la SNES podía con juegos que antes requerían una recreativa. Fue el argumento definitivo en la guerra de los 16 bits.</p>\r\n\r\n<p>En España, Street Fighter II fue el último gran hit de los salones recreativos antes de que las consolas domésticas comenzaran a vaciarlos definitivamente. Muchos recuerdan las tardes de 1992 y 1993 en el recreativo local como <strong>la última gran época dorada</strong> de las maquinitas.</p>'),
	(18, 12, 1, 'METRO CITY NECESITA UN HÉROE', '<p>Corría 1989 cuando Capcom anunció que su próximo proyecto se llamaría <strong>Street Fighter \'89</strong>. Era, en principio, una secuela del primer Street Fighter. Pero algo cambió en el proceso de desarrollo y el juego llegó a los salones recreativos con otro nombre: <strong>Final Fight</strong>. Y con ese cambio de nombre llegó también un cambio de historia que definió un género.</p>\r\n<p>La Mad Gear, la banda criminal más poderosa de Metro City, ha secuestrado a <strong>Jessica</strong>, hija del alcalde <strong>Mike Haggar</strong>. Error garrafal. Porque Haggar no es un alcalde cualquiera: es un ex-luchador profesional de 230 kilos de puro músculo. Junto a <strong>Cody</strong>, novio de Jessica, y <strong>Guy</strong>, maestro del ninjutsu, los tres hombres van a machacar a medio Metro City hasta recuperarla.</p>\r\n<p>Ese es el argumento. Sencillo, directo, sin pretensiones. Y perfecto.</p>'),
	(19, 12, 2, 'EL SISTEMA DE JUEGO: PUÑOS, PATADAS Y TUBOS DE HIERRO', '<p>Final Fight no inventó el beat \'em up —eso lo hizo Renegade en 1986— pero sí lo <strong>perfeccionó hasta hacerlo irreconocible</strong>. Los sprites eran enormes, la animación era fluida, los golpes sonaban como dios manda y la pantalla se llenaba de enemigos que reaccionaban de forma creíble al recibir impactos.</p>\r\n<p>El sistema de combate era sencillo pero con más profundidad de la que parecía. Tenías golpe básico, salto, agarre y el <strong>ataque especial</strong> que te costaba energía pero despejaba la pantalla cuando te veías rodeado. Cada personaje tenía un estilo diferente: Haggar era lento pero demoledor, Cody era el más equilibrado y Guy era el más rápido y ágil.</p>\r\n<p>Los escenarios se dividían en zonas de Metro City —el Slum, el Subway, el Industrial Area, el Bay Area y el Uptown— cada una con su paleta visual propia y sus enemigos característicos. No había dos fases iguales en atmósfera.</p>'),
	(20, 12, 3, 'LOS TRES HÉROES', '<p><strong>Mike Haggar</strong> — Alcalde y ex-luchador profesional. Lento, pero cada golpe que conecta hace temblar la pantalla. Su pile driver es uno de los movimientos más satisfactorios de la historia del arcade. Cuando Haggar agarra a un enemigo, el enemigo ya ha perdido.</p>\r\n<p><strong>Cody Travers</strong> — El personaje recomendado para los que empiezan. Velocidad y potencia en proporciones perfectas. Su uppercut es devastador y su combo básico es el más fácil de ejecutar. Años después reaparecería en Street Fighter Alpha como un ex-convicto.</p>\r\n<p><strong>Guy</strong> — Para jugadores experimentados. Su velocidad le permite encadenar golpes antes de que los enemigos se recuperen, pero su daño por golpe es el más bajo. Dominarlo requiere práctica. Cuando lo dominas, te sientes invencible.</p>'),
	(21, 12, 4, 'LOS JEFES DE LA MAD GEAR', '<p>Final Fight tiene algunos de los mejores jefes del género. Cada uno con personalidad propia y patrón de ataque distinto:</p>\r\n<p><strong>Damnd</strong> (Zona 1) — El matón clásico. Silba para llamar refuerzos cuando pierde energía. Engañosamente difícil para ser el primer jefe.</p>\r\n<p><strong>Sodom</strong> (Zona 2) — Gigante con katanas, fan de la cultura japonesa. Reaparece en Street Fighter Alpha.</p>\r\n<p><strong>Edi E.</strong> (Zona 3) — Un sheriff enorme con pistola. El más frustrante del juego. Su disparo a distancia obliga a cambiar completamente la estrategia.</p>\r\n<p><strong>Rolento</strong> (Zona 4) — Ágil, peligroso, con granadas. El favorito de muchos jugadores.</p>\r\n<p><strong>Abigail</strong> (Zona 5) — Un gigante que ocupa media pantalla. Sus golpes quitan un tercio de la energía de un toque.</p>\r\n<p><strong>Belger</strong> (Zona 6) — El cerebro de la Mad Gear. En silla de ruedas, con ballesta. El enfrentamiento final en lo alto del edificio es puro cine de acción.</p>'),
	(22, 12, 5, 'LA MÚSICA Y EL SONIDO', '<p>La banda sonora de Final Fight es obra de <strong>Yoshihiro Sakaguchi</strong> y es una de las mejores de la era CPS-1. Cada zona tiene su propio tema musical que encaja a la perfección con la atmósfera del escenario: el Slum suena amenazante y urbano, el Subway tiene ese aire claustrofóbico, el Industrial Area es pesado y maquinal.</p>\r\n<p>Los efectos de sonido son igualmente contundentes. El crack seco de un puñetazo bien conectado, el quejido de los enemigos al recibir un agarre de Haggar, el sonido metálico de un tubo de hierro... todo contribuye a esa sensación de peso y contundencia que distingue a Final Fight de cualquier competidor de la época.</p>\r\n<p>El tema del Stage 1 —el Slum— es probablemente el más reconocible. Esa línea de bajo pulsante ha quedado grabada a fuego en la memoria de toda una generación de jugadores de recreativas.</p>'),
	(23, 12, 6, 'EL LEGADO', '<p>Definió el beat \'em up moderno. Estableció los estándares de diseño de niveles, de variedad de enemigos y de diseño de personajes jugables que todos los que vinieron después —Streets of Rage, Battletoads, Knights of the Round— intentaron igualar. Ninguno lo superó.</p>\r\n<p>Metro City y sus personajes tuvieron vida propia mucho después del juego original. Haggar apareció en Marvel vs. Capcom 3. Cody y Guy en Street Fighter Alpha y más tarde en Street Fighter V. La Mad Gear siguió siendo referenciada décadas después. Pocos juegos de arcade pueden decir lo mismo.</p>'),
	(24, 14, 1, 'EL COMECOCOS QUE LO CAMBIÓ TODO', '<p>\r\n  Corría 1980 cuando <strong>Toru Iwatani</strong>, un diseñador de Namco de 25 años, se sentó a comer una pizza y le quitó un trozo. Miró el hueco. Y ahí estaba: la silueta de un personaje que iba a cambiar la historia de los videojuegos. La historia es probablemente apócrifa, pero es tan buena que da igual si es verdad o no.\r\n</p>\r\n<p>\r\n  Lo que sí es verdad es que hasta <strong>Pac-Man</strong> el arcade era territorio casi exclusivamente masculino. Disparos, combates, naves. Iwatani quería hacer algo diferente —algo que atrajera también a las mujeres, a las parejas, a gente que normalmente no metía monedas en una máquina. El resultado fue un juego sin violencia explícita, con un protagonista con personalidad y una mecánica tan simple que cualquiera la entendía en diez segundos.\r\n</p>\r\n<p>\r\n  En Japón se llamó <em>Puck Man</em>. En Estados Unidos lo rebautizaron <strong>Pac-Man</strong> para evitar que los vándalos convirtieran la P en otra cosa. Buena decisión.\r\n</p>'),
	(25, 14, 2, 'EL LABERINTO, LOS PUNTOS Y LOS FANTASMAS', '<p>\r\n  La mecánica de Pac-Man es tan elegante que cabe en una frase: <strong>come todos los puntos del laberinto sin que te atrapen los fantasmas</strong>. Eso es todo. No hay historia, no hay niveles con narrativa, no hay jefes finales. Solo el laberinto, 240 puntos pequeños, 4 puntos grandes —las <strong>Power Pellets</strong>— y cuatro fantasmas que te persiguen con una inteligencia artificial que en 1980 era pura magia.\r\n</p>\r\n<div class="char-stats-grid" style="margin:16px 0">\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">PUNTOS NORMALES</div>\r\n    <div class="char-stat-val">10 pts.</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">POWER PELLET</div>\r\n    <div class="char-stat-val">50 pts.</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">FANTASMA COMIDO</div>\r\n    <div class="char-stat-val">200–1600 pts.</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">FRUTA BONUS</div>\r\n    <div class="char-stat-val">100–5000 pts.</div>\r\n  </div>\r\n</div>\r\n<p>\r\n  Las Power Pellets son el corazón del diseño. Durante unos segundos los fantasmas se vuelven azules, vulnerables, y el cazado se convierte en cazador. Es el primer ejemplo documentado de un <strong>power-up que invierte la dinámica de juego</strong> —una idea tan buena que llevan cuarenta años copiándola en todos los géneros imaginables.\r\n</p>\r\n<p>\r\n  El laberinto tiene dos salidas laterales que te teletransportan al lado contrario. Un detalle pequeño que añade una capa de estrategia enorme: a veces la mejor huida es cruzar la pantalla de lado a lado. Los fantasmas te siguen, pero más despacio por ese pasillo. Aprenderlo marca la diferencia entre morir en el nivel 3 y llegar al nivel 20.\r\n</p>'),
	(26, 14, 3, 'LOS CUATRO FANTASMAS', '<p>\r\n  No son cuatro enemigos idénticos. Cada fantasma tiene su propio algoritmo de movimiento, su propia personalidad, y en los créditos originales hasta tienen nombre en japonés y apodo en inglés.\r\n</p>\r\n<div class="char-stats-grid" style="margin-bottom:16px">\r\n  <div class="char-stat-item" style="border-left:3px solid #ff0000;padding-left:12px">\r\n    <div class="char-stat-label">BLINKY — SHADOW</div>\r\n    <div class="char-stat-val" style="color:#aaa;font-size:13px;margin-top:4px">El rojo · El perseguidor</div>\r\n    <div style="margin-top:8px;font-family:\'Rajdhani\',sans-serif;font-size:14px;color:#777;line-height:1.6">\r\n      Te persigue directamente. Cuantos menos puntos quedan en el laberinto, más rápido se vuelve. En los niveles avanzados entra en modo <em>Cruise Elroy</em> y se convierte en una pesadilla imposible de despistar.\r\n    </div>\r\n  </div>\r\n  <div class="char-stat-item" style="border-left:3px solid #ffb8ff;padding-left:12px">\r\n    <div class="char-stat-label">PINKY — SPEEDY</div>\r\n    <div class="char-stat-val" style="color:#aaa;font-size:13px;margin-top:4px">El rosa · El emboscador</div>\r\n    <div style="margin-top:8px;font-family:\'Rajdhani\',sans-serif;font-size:14px;color:#777;line-height:1.6">\r\n      No va donde estás sino donde va a estar. Apunta cuatro casillas por delante de Pac-Man. Si vas hacia arriba, te está esperando arriba. El más difícil de leer para un jugador nuevo.\r\n    </div>\r\n  </div>\r\n  <div class="char-stat-item" style="border-left:3px solid #00ffff;padding-left:12px">\r\n    <div class="char-stat-label">INKY — BASHFUL</div>\r\n    <div class="char-stat-val" style="color:#aaa;font-size:13px;margin-top:4px">El azul · El impredecible</div>\r\n    <div style="margin-top:8px;font-family:\'Rajdhani\',sans-serif;font-size:14px;color:#777;line-height:1.6">\r\n      Su movimiento depende de la posición de Blinky. Es el fantasma más difícil de predecir porque su comportamiento cambia según lo que haga otro. A veces parece tonto. A veces te corta el paso perfectamente.\r\n    </div>\r\n  </div>\r\n  <div class="char-stat-item" style="border-left:3px solid #ffb852;padding-left:12px">\r\n    <div class="char-stat-label">CLYDE — POKEY</div>\r\n    <div class="char-stat-val" style="color:#aaa;font-size:13px;margin-top:4px">El naranja · El errático</div>\r\n    <div style="margin-top:8px;font-family:\'Rajdhani\',sans-serif;font-size:14px;color:#777;line-height:1.6">\r\n      Persigue a Pac-Man hasta que se acerca demasiado —a menos de ocho casillas— y entonces huye en dirección contraria. Parece el más inofensivo. No lo subestimes: su comportamiento errático lo convierte en el más peligroso en espacios cerrados.\r\n    </div>\r\n  </div>\r\n</div>'),
	(27, 14, 4, 'EL SONIDO QUE TODOS CONOCEN', '<div class="char-bio">\r\n  <p>\r\n    <em>Waka waka waka waka.</em> Es el sonido más reconocible de la historia de los videojuegos. No hay encuesta, no hay ranking, no hay generación que lo discuta. Antes de que existiera la música de Super Mario, antes del tema de Tetris, estaba el waka waka de Pac-Man.\r\n  </p>\r\n  <p>\r\n    La sintonía de inicio —esos cuatro compases que suenan antes de cada partida— lleva más de cuarenta años grabada en la memoria colectiva. La compuso <strong>Toshio Kai</strong> en el hardware de sonido más limitado que puedas imaginar. Con tres canales y unas pocas ondas cuadradas creó algo que cualquier persona en el planeta reconoce al instante. Eso no es tecnología. Es talento.\r\n  </p>\r\n</div>'),
	(28, 14, 5, 'EL VEREDICTO', '<div class="char-bio">\r\n  <p>\r\n    Pac-Man no es el mejor juego arcade que existe. Hay títulos más profundos, más espectaculares, más adictivos en términos puramente mecánicos. Pero ninguno ha hecho lo que hizo Pac-Man en 1980: <strong>demostrar que los videojuegos podían ser para todo el mundo</strong>.\r\n  </p>\r\n  <p>\r\n    Fue el primer juego con un protagonista reconocible. El primero en generar merchandising masivo —ropa, juguetes, cereales, una serie de animación. El primero en cruzar la barrera entre el arcade y la cultura popular sin pedir permiso. Antes de Pac-Man los videojuegos eran una cosa rara. Después de Pac-Man eran parte de la vida cotidiana.\r\n  </p>\r\n</div>\r\n<div class="char-stats-grid" style="margin-top:20px">\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">DISEÑO</div>\r\n    <div class="char-stat-val" style="color:var(--amarillo)">10/10</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">JUGABILIDAD</div>\r\n    <div class="char-stat-val" style="color:var(--amarillo)">9/10</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">SONIDO</div>\r\n    <div class="char-stat-val" style="color:var(--amarillo)">10/10</div>\r\n  </div>\r\n  <div class="char-stat-item">\r\n    <div class="char-stat-label">LEGADO</div>\r\n    <div class="char-stat-val" style="color:var(--amarillo)">10/10</div>\r\n  </div>\r\n</div>'),
	(29, 15, 1, 'El mundo que Capcom construyó', '<p>Corría 1992 y Capcom ya sabía perfectamente lo que hacía. Después del éxito arrollador de <strong>Final Fight</strong>, tenía la fórmula perfecta del beat \'em up: pantallas de scroll lateral, enemigos a puñetazos y cooperativo para dos. Pero esta vez decidieron hacer algo diferente. Algo más raro. Algo que nadie esperaba.</p>\r\n\r\n<p>Cogieron un cómic underground americano llamado <em>Xenozoic Tales</em>, de Mark Schultz, y lo convirtieron en máquina recreativa. El resultado fue <strong>Cadillacs and Dinosaurs</strong>: un universo en el que el mundo tal y como lo conocemos ha colapsado, la naturaleza ha recuperado el terreno y los dinosaurios campan a sus anchas por una Tierra del siglo XXVI que huele a gasolina, cuero y peligro.</p>\r\n\r\n<p>No era el típico escenario de callejones y macarras. Era otra cosa.</p>'),
	(30, 15, 2, 'Cuatro formas de repartir estopa', '<p>El juego pone a tu disposición cuatro personajes, cada uno con su propio estilo de pelea:</p>\r\n\r\n<p><strong>Jack Tenrec</strong> — el protagonista. Mecánico, ecologista y con los puños más equilibrados del grupo. El personaje para el que está diseñado el juego.</p>\r\n\r\n<p><strong>Hannah Dundee</strong> — diplomática y ágil. Más rápida que Jack pero con menos pegada. La favorita de los jugadores con experiencia que saben aprovechar la velocidad.</p>\r\n\r\n<p><strong>Mustapha Cairo</strong> — el más fuerte del grupo. Lento como una nevera pero cada golpe suyo vale por dos. Para quien quiere arrasar sin pensar demasiado.</p>\r\n\r\n<p><strong>Mess O\'Bradovich</strong> — grandullón y con aspecto de oso. Potencia bruta pura. El personaje que elegías cuando querías que los enemigos salieran volando por la pantalla.</p>\r\n\r\n<blockquote>En cooperativo a cuatro jugadores, el salón recreativo se convertía en un campo de batalla. Cada uno con su personaje, empujándose, robándose las armas y culpándose mutuamente cuando alguien perdía una vida.</blockquote>'),
	(31, 15, 3, 'El hardware detrás de la bestia', '<p>Cadillacs and Dinosaurs corría sobre la placa <strong>CPS-1</strong> de Capcom, la misma que ya había dado vida a Street Fighter II y Final Fight. En 1992, esa placa seguía siendo una barbaridad técnica.</p>\r\n\r\n<p>Los sprites eran enormes y detallados. Los dinosaurios —que aparecen como enemigos y como elementos del escenario— tenían un tamaño y una animación que dejaban con la boca abierta. Ver a un T-Rex irrumpir en pantalla por primera vez era un momento de pura incredulidad.</p>\r\n\r\n<p>La paleta de colores era exuberante: rojos oxidados, verdes selváticos, el cromo brillante de los Cadillacs de los años 50. Capcom sabía que el impacto visual era la primera moneda que te hacía meter la segunda.</p>\r\n\r\n<p>Y la música. <em>Dios, la música.</em> Ese mezcla de rock, jazz y épica orquestal que sonaba a un volumen indecente desde los altavoces de la máquina y que podías escuchar desde la puerta del recreativo.</p>'),
	(32, 15, 4, 'Armas, dinosaurios y caos', '<p>Lo que diferenciaba a Cadillacs del resto de beat \'em ups de la época era la variedad. No era solo pegar. Era pegar <em>con estilo</em>.</p>\r\n\r\n<p>Podías recoger armas del suelo: pistolas, lanzacohetes, cuchillos, palos. Podías usarlas contra los enemigos o, en uno de esos momentos de gloria cooperativa, dársela a tu compañero cuando la necesitaba más que tú.</p>\r\n\r\n<p>Pero lo que nadie olvidaba eran los dinosaurios. Porque los dinosaurios no solo eran decorado. <strong>Eran una herramienta</strong>. Si conseguías atraer a un enemigo hacia uno, el dinosaurio hacía el trabajo por ti. Gratuito. Eficiente. Satisfactorio de una manera que las palabras no terminan de explicar.</p>\r\n\r\n<p>Algunos jefes eran directamente dinosaurios. Enormes, lentos y con la capacidad de llenarte la pantalla de muerte en dos segundos si no sabías moverte.</p>\r\n\r\n<hr>\r\n\r\n<p>El juego tenía <strong>siete niveles</strong>, cada uno con su propia ambientación: las ruinas de la ciudad, la jungla, las alcantarillas, el mercado... Un desfile de escenarios que mantenía el ritmo y evitaba que te aburrieras.</p>'),
	(33, 15, 5, 'Por qué lo recuerdas aunque no lo recuerdes', '<p>Cadillacs and Dinosaurs no fue el juego más vendido de su año. No tuvo la fama instantánea de Street Fighter II ni la presencia cultural de Mortal Kombat. Pero en los recreativos españoles de principios de los 90, <strong>estaba</strong>. Ocupaba ese rincón privilegiado donde las máquinas buenas siempre acababan.</p>\r\n\r\n<p>Si tenías entre 8 y 15 años en 1992 y pisaste un salón recreativo, hay muchas posibilidades de que te hayas quedado mirando esa pantalla sin meter ficha, viendo a otros jugar, calculando si te llegaba para una partida.</p>\r\n\r\n<p>El juego tuvo una serie de animación americana en 1993 —<em>Cadillacs and Dinosaurs: The Animated Series</em>— que ayudó a mantener vivo el universo un poco más. Pero nunca hubo una segunda parte arcade. La CPS-1 fue dando paso a la CPS-2, los gustos cambiaron, y Capcom siguió adelante.</p>\r\n\r\n<blockquote>Lo que quedó fue el recuerdo de esas tardes. El rugido del T-Rex. El sonido de un Cadillac arrancando. Y la sensación de que el mundo del siglo XXVI, aunque horrible, tenía algo de fascinante.</blockquote>'),
	(34, 15, 6, 'Veredicto', '<p>Cadillacs and Dinosaurs es un beat \'em up de Capcom en estado puro: sólido, espectacular para su época y con una ambientación que no ha envejecido mal. No reinventa el género —Final Fight ya había puesto el listón dos años antes— pero lo ejecuta con una personalidad visual y sonora que pocos juegos de la época podían igualar.</p>\r\n\r\n<p>Si buscas pureza arcade de los 90, aquí la tienes. Y si nunca lo has jugado, MAME está a un par de clics.</p>\r\n\r\n<p><strong>Lo mejor:</strong> La ambientación única, los dinosaurios como elemento de juego, el cooperativo a cuatro, la música.<br>\r\n<strong>Lo peor:</strong> Puede resultar repetitivo en solitario. Los jefes finales son esponjas de daño que alargan artificialmente la duración.<br>\r\n<strong>Imprescindible si:</strong> Disfrutaste de Final Fight, Knights of the Round o cualquier beat \'em up de Capcom de esa era.</p>'),
	(35, 17, 0, 'Yabba-Dabba-Doo en forma de bola de acero', '<p>1994 fue un año extraño para el cine. Hollywood decidió que las series de animación clásicas de Hanna-Barbera merecían versiones de acción real con presupuestos enormes, y la primera en saltar a la pantalla grande fue <strong>Los Picapiedra</strong>. John Goodman como Fred Flintstone, Rick Moranis como Barney Rubble, y un Bedrock que costó más de 46 millones de dólares construir.</p>\r\n\r\n<p>Williams vio la oportunidad y encargó a <strong>Steve Ritchie</strong> — uno de los diseñadores de mesas más respetados de la historia — que convirtiera esa película en pinball. El resultado llegó ese mismo año: una mesa que capturaba el espíritu prehistórico-moderno de los Picapiedra con una fidelidad sorprendente y un juego más profundo de lo que la licencia hacía prever.</p>\r\n\r\n<p>No era la primera vez que Williams apostaba por licencias de cine para sus mesas. Pero The Flintstones tenía algo que muchas otras no tenían: personalidad propia dentro del tablero.</p>'),
	(36, 17, 1, 'La mesa — lo que ves antes de lanzar', '<p>Lo primero que llama la atención de The Flintstones es el <strong>color</strong>. La mesa es una explosión de naranja, amarillo y marrón — la paleta característica de Bedrock — que contrasta perfectamente con los plastics translúcidos y las ilustraciones del backglass. Fred y Barney te miran desde arriba con esa expresión de satisfacción que solo tienen los personajes de dibujos animados de los años 60.</p>\r\n\r\n<p>El layout de la mesa incluye:</p>\r\n\r\n<p><strong>La rampa del Bedrock Express</strong> — la rampa principal de la mesa, que simula el tren prehistórico de la serie. Completarla repetidamente activa los modos principales del juego.</p>\r\n\r\n<p><strong>El hoyo del Dino</strong> — el kicker central que dispara la bola hacia los targets superiores. Cuando Dino ladra desde el altavoz al mismo tiempo, el efecto es perfecto.</p>\r\n\r\n<p><strong>Los bumpers del Quarry</strong> — situados en la zona superior, representan la cantera donde Fred trabaja. Activos y ruidosos, como debe ser.</p>\r\n\r\n<p><strong>Los targets de los personajes</strong> — completar los grupos de targets activa voces y modos relacionados con Fred, Barney, Wilma y Betty.</p>'),
	(37, 17, 2, 'El sonido — la mitad del juego', '<p>Williams en 1994 ya dominaba el audio en pinball como nadie. The Flintstones tiene <strong>voces digitalizadas</strong> de los actores de la película — o al menos de los dobladores — que suenan en respuesta a casi todo lo que pasa en la mesa. Fred grita "¡Yabba-Dabba-Doo!" cuando completas una rampa. Barney comenta tus fallos con ese tono entre inocente y condescendiente que le caracteriza. Dino ladra cuando la bola pasa por su zona.</p>\r\n\r\n<p>La música sigue los temas instrumentales de la película, con ese estilo orquestal de grandes estudios que Hollywood usaba en los 90. No es la música de la serie original — esa quedaría para siempre en la memoria colectiva — pero cumple su función de mantener la energía del juego.</p>\r\n\r\n<blockquote>En un salón recreativo de 1994, escuchar "¡Yabba-Dabba-Doo!" saliendo de un pinball desde el otro lado del local era suficiente para acercarse a ver de qué se trataba.</blockquote>'),
	(38, 17, 3, 'Modos de juego', '<p>The Flintstones sigue la estructura WPC de Williams: modos activados por secuencias de targets y rampas, con un modo multibola como clímax central.</p>\r\n\r\n<p><strong>Bedrock Express Multiball</strong> — el modo más esperado. Completar la rampa varias veces activa el multiball con tres bolas simultáneas. La mesa se vuelve caótica de la mejor manera posible.</p>\r\n\r\n<p><strong>Bowling for Dinos</strong> — modo especial activado desde el hoyo central. La puntuación multiplica con cada hit consecutivo. Fácil de entrar, difícil de aprovechar bien.</p>\r\n\r\n<p><strong>Modo Película</strong> — una secuencia de objetivos que recorre las escenas principales de la película. Completarlo desbloquea el Wizard Mode.</p>\r\n\r\n<p><strong>Yabba-Dabba-Doo Jackpot</strong> — el jackpot máximo del multiball. Conseguirlo requiere completar la rampa con dos bolas activas al mismo tiempo. Cuando ocurre, Fred lo celebra como si le hubiera tocado la lotería.</p>\r\n\r\n<hr>\r\n\r\n<p>La profundidad de reglas no es la más compleja que Williams produjo en esa época — eso lo dejaron para títulos como <em>The Twilight Zone</em> o <em>Medieval Madness</em> — pero está muy bien equilibrada para ser accesible sin resultar aburrida para los jugadores veteranos.</p>'),
	(39, 17, 4, 'Steve Ritchie — el hombre detrás de la mesa', '<p>Steve Ritchie no es solo un diseñador de pinball. Es una leyenda. Responsable de mesas como <strong>Black Knight</strong>, <strong>Terminator 2</strong>, <strong>Star Trek: The Next Generation</strong> y <strong>AC/DC</strong>, Ritchie tiene una firma inconfundible: mesas rápidas, fluidas, con rampas largas que premian el control y layouts que invitan a la repetición.</p>\r\n\r\n<p>The Flintstones no es su mesa más ambiciosa, pero sí una de las más divertidas. Ritchie entendió que una licencia familiar como los Picapiedra pedía accesibilidad antes que complejidad, y diseñó una mesa que engancha desde la primera bola sin abrumar con reglas.</p>\r\n\r\n<p>El resultado es un pinball que se disfruta igual con ocho años que con cuarenta. No muchas mesas pueden decir lo mismo.</p>'),
	(40, 17, 5, 'Veredicto', '<p>The Flintstones es un pinball sólido, divertido y con una personalidad visual y sonora muy bien construida. No está en el Olimpo de Williams — ese lugar lo ocupan The Twilight Zone, Medieval Madness o Addams Family — pero es una mesa que merece más respeto del que suele recibir.</p>\r\n\r\n<p>Para los coleccionistas es una opción interesante: no tiene el precio desorbitado de los grandes clásicos, el sistema WPC es robusto y los repuestos son fáciles de conseguir. Para quien quiera iniciarse en el coleccionismo de pinball sin hipotecarse, The Flintstones es una puerta de entrada muy digna.</p>\r\n\r\n<p><strong>Lo mejor:</strong> Fluidez de juego, voces y sonido excepcionales para 1994, multibola satisfactorio, diseño visual muy fiel a la licencia.<br>\r\n<strong>Lo peor:</strong> Reglas algo simples comparado con otros Williams de la época, el modo película se agota rápido.<br>\r\n<strong>Imprescindible si:</strong> Eres fan de los Picapiedra, quieres iniciarte en el coleccionismo o simplemente buscas una mesa Williams fiable y divertida.</p>'),
	(41, 18, 1, 'El rey de los pinballs', '<p>Hay un número que lo resume todo: <strong>20.270</strong>. Esas son las unidades que Williams fabricó de The Addams Family entre 1992 y 1993. Ningún pinball en la historia ha vendido más. Ninguno se ha acercado siquiera. En un mercado donde vender 5.000 unidades ya era un éxito rotundo, The Addams Family fue una anomalía estadística que nadie había previsto y que nadie ha repetido desde entonces.</p>\r\n\r\n<p>Detrás de ese número hay una confluencia perfecta de factores: una licencia en el momento exacto — la película de Barry Sonnenfeld acababa de arrasar en taquilla en 1991 — un diseñador en estado de gracia y una mesa que, independientemente de la licencia, es sencillamente uno de los mejores pinballs que se han construido jamás.</p>\r\n\r\n<p>El diseñador era <strong>Pat Lawlor</strong>. Y The Addams Family fue su obra maestra.</p>'),
	(42, 18, 2, 'Pat Lawlor — el hombre que cambió el pinball', '<p>Pat Lawlor llegó a Williams en los años 80 con una obsesión: hacer pinballs que contaran historias. Que tuvieran personajes, arcos narrativos, momentos climáticos. Que el jugador no solo golpeara targets sino que viviera algo.</p>\r\n\r\n<p>Con The Addams Family lo consiguió de una manera que nadie había visto antes. La mesa no es solo un conjunto de rampas y bumpers — es una <em>obra de teatro</em> en miniatura. Cada modo de juego es un capítulo. Cada voz digitalizada es un personaje. Cada partida es diferente porque los modos se pueden activar en cualquier orden y la historia se construye de forma distinta cada vez.</p>\r\n\r\n<p>Lawlor repetiría la fórmula dos años después con <strong>The Twilight Zone</strong> — otra obra maestra — pero The Addams Family fue el primer experimento. El que demostró que el pinball podía ser algo más que un juego de reflejos.</p>\r\n\r\n<blockquote>Cuando una mesa te hace reír, emocionarte y maldecir en la misma partida, algo muy especial ha ocurrido en su diseño.</blockquote>'),
	(43, 18, 3, 'La mesa — anatomía de un clásico', '<p>Lo primero que ves es <strong>La Cosa</strong> — la mano descarnada que sale de una caja en el centro de la mesa. No es solo decoración: La Cosa es el elemento interactivo principal del juego. Cuando completas ciertos objetivos, La Cosa sale de su caja y recoge la bola. Es el truco de magia más satisfactorio del pinball.</p>\r\n\r\n<p>El layout incluye elementos que se convirtieron en referencia para toda la industria:</p>\r\n\r\n<p><strong>La rampa del Tren Fantasma</strong> — la rampa principal, larga y rápida, que recorre la parte trasera de la mesa. Completarla repetidamente avanza en los modos principales.</p>\r\n\r\n<p><strong>El ático</strong> — la zona superior izquierda donde vive Abuelo. Activarlo desbloquea el modo de mayor puntuación de la mesa.</p>\r\n\r\n<p><strong>El cementerio</strong> — targets en la zona central que representan las lápidas de la familia. Completarlos activa voces y modos secundarios.</p>\r\n\r\n<p><strong>La silla eléctrica de Gomez</strong> — un bumper especial en la esquina derecha con una animación propia cuando se activa.</p>\r\n\r\n<p><strong>Los bumpers de alta velocidad</strong> — situados en la zona superior, disparan la bola a una velocidad que en 1992 era inédita en el mercado.</p>'),
	(44, 18, 4, 'Las voces — Raul Julia y Anjelica Huston en tu salón', '<p>Williams consiguió algo que ningún otro fabricante había logrado hasta entonces: que los actores principales de la película prestaran sus voces para el pinball. <strong>Raul Julia</strong> como Gomez y <strong>Anjelica Huston</strong> como Morticia grabaron decenas de frases específicamente para la máquina.</p>\r\n\r\n<p>El resultado es que cada partida es una conversación con los Addams. Gomez celebra tus éxitos con ese entusiasmo desmedido que solo él tiene. Morticia comenta tus fallos con su calma inquietante. Miércoles aparece en los momentos más inesperados. Fester tiene su propio monólogo cuando activas su modo.</p>\r\n\r\n<p>La tecnología de audio de Williams en 1992 era la mejor del mercado — sistema estéreo, altavoces en el backglass y en la caja, voces digitalizadas a una calidad que dejaba obsoleto todo lo anterior. En un salón recreativo, escuchar a Raul Julia gritar <em>"¡MAMUSHKA!"</em> desde el otro lado de la sala era publicidad suficiente para acercarse.</p>\r\n\r\n<hr>\r\n\r\n<p>Hay una frase de Gomez que los jugadores veteranos conocen de memoria: <em>"¡Cosa, ven aquí!"</em> — el momento justo antes de que La Cosa salga de su caja. Treinta años después, sigue provocando una sonrisa involuntaria.</p>'),
	(45, 18, 5, 'Los 13 modos — una mesa dentro de otra mesa', '<p>The Addams Family tiene <strong>13 modos de juego</strong>, uno por cada miembro de la familia. Para acceder al modo final — el Wizard Mode llamado <strong>TOUR THE MANSION</strong> — hay que completarlos todos. En una sola partida. Sin perder la bola antes de tiempo.</p>\r\n\r\n<p>Nadie lo consigue en las primeras partidas. Casi nadie lo consigue en las primeras semanas. Es el objetivo que mantiene al jugador volviendo una y otra vez.</p>\r\n\r\n<p>Los modos más memorables:</p>\r\n\r\n<p><strong>SEANCE</strong> — multiball con tres bolas. El modo más caótico y el que más puntos da si se controla bien.</p>\r\n\r\n<p><strong>GRAVEYARD AT MIDNIGHT</strong> — modo de alta velocidad donde los bumpers multiplican su valor. La mesa se vuelve impredecible.</p>\r\n\r\n<p><strong>ELECTRIC CHAIR</strong> — modo de tiempo limitado donde cada target tiene un valor creciente. Requiere precisión absoluta.</p>\r\n\r\n<p><strong>MAMUSHKA</strong> — el jackpot máximo. Conseguirlo en multiball mientras suena Gomez gritando su nombre es uno de los momentos más satisfactorios que el pinball ha dado jamás.</p>\r\n\r\n<p><strong>TOUR THE MANSION</strong> — el Wizard Mode. Si llegas aquí, la mesa literalmente te da la bienvenida como si fuera la primera vez. Los Addams te reciben en casa. Has ganado.</p>'),
	(46, 18, 6, 'Por qué sigue siendo el mejor**', '<p>Treinta años después de su fabricación, The Addams Family sigue siendo la primera respuesta cuando alguien pregunta cuál es el mejor pinball de la historia. No porque sea el más técnicamente avanzado — el hardware de 1992 tiene sus limitaciones obvias — sino porque ninguna mesa ha conseguido equilibrar tan perfectamente la accesibilidad con la profundidad.</p>\r\n\r\n<p>Un niño de ocho años puede jugar y divertirse. Un jugador veterano de veinte años de experiencia puede seguir encontrando cosas nuevas. La curva de aprendizaje es perfecta: cada partida enseña algo, cada sesión muestra un modo que no habías visto, cada vez que llegas un poco más lejos quieres volver a intentarlo.</p>\r\n\r\n<p>Para los coleccionistas es el objeto de deseo por excelencia. Los precios llevan años subiendo — una unidad en buen estado supera los 6.000€ sin dificultad — pero la demanda no baja. Hay mesas más raras, más caras y más exclusivas. Pero ninguna tiene el peso histórico de The Addams Family.</p>\r\n\r\n<blockquote>Cuando alguien te pregunta qué es el pinball y no sabes cómo explicarlo, le pones delante de esta mesa y esperas. En treinta segundos lo entiende solo.</blockquote>'),
	(48, 19, 1, 'Steve Ritchie y la película del año', '<p>1991 fue el año de Terminator 2. La película de James Cameron arrasó en taquilla, redefinió los efectos especiales y convirtió a Arnold Schwarzenegger en el actor más reconocible del planeta. Williams vio la oportunidad y encargó a <strong>Steve Ritchie</strong> — el mismo que había diseñado Black Knight, High Speed y Firepower — que convirtiera esa película en pinball.</p>\r\n\r\n<p>El resultado llegó el mismo año que la película: una mesa que capturaba la energía, la velocidad y la brutalidad de T2 con una fidelidad que ningún otro fabricante habría conseguido. Ritchie no hizo una mesa con licencia de película — hizo una película con licencia de mesa.</p>\r\n\r\n<p>En los salones recreativos de 1991 y 1992, Terminator 2 era la máquina con más cola. Siempre.</p>'),
	(49, 19, 2, 'El cañón de plasma — la revolución', '<p>Antes de Terminator 2, los pinballs tenían un lanzador. Uno. El plunger de toda la vida, en la esquina derecha, que disparaba la bola al inicio de cada turno.</p>\r\n\r\n<p>Steve Ritchie cambió eso para siempre.</p>\r\n\r\n<p>El <strong>Cañón de Plasma</strong> — un lanzador secundario situado en el centro-izquierda de la mesa — dispara la bola hacia la zona superior del playfield de una manera que ningún otro mecanismo había conseguido hasta entonces. No es solo un truco visual: el cañón abre rutas de juego completamente nuevas, activa modos específicos y da una sensación de potencia que el plunger estándar nunca podría dar.</p>\r\n\r\n<p>Fue el primer mecanismo de este tipo en un pinball de producción masiva. Williams lo patentó, lo protegió y lo convirtió en referencia. Treinta años después, el cañón de plasma sigue siendo el elemento más imitado de la historia del pinball moderno.</p>\r\n\r\n<blockquote>La primera vez que disparas el cañón de plasma en una T2 en buen estado, entiendes exactamente por qué este juego vendió 15.000 unidades.</blockquote>'),
	(50, 19, 3, 'La mesa — anatomía de una máquina de guerra', '<p>El layout de Terminator 2 es pura ingeniería de velocidad. Ritchie diseñó mesas rápidas toda su vida — High Speed ya tenía ese ADN en 1986 — pero T2 llevó esa filosofía al extremo.</p>\r\n\r\n<p><strong>La rampa del camión</strong> — la rampa principal de la mesa, larga y con una curva pronunciada que acelera la bola hasta velocidades que hacen que el ojo apenas pueda seguirla. Completarla repetidamente activa los modos principales.</p>\r\n\r\n<p><strong>Los targets del T-1000</strong> — una fila de targets en la zona central que representan al antagonista de la película. Derribarlos activa el modo de mayor puntuación de la mesa.</p>\r\n\r\n<p><strong>El hoyo del Skynet</strong> — el kicker central que dispara la bola hacia el cañón de plasma. La conexión entre los dos mecanismos principales es lo que hace que la mesa fluya de una manera única.</p>\r\n\r\n<p><strong>Los bumpers de alta tensión</strong> — situados en la zona superior, con una velocidad de respuesta que en 1991 era la más rápida del mercado. Cuando la bola entra en esa zona, el sonido y la velocidad son pura adrenalina.</p>\r\n\r\n<p><strong>El backglass</strong> — una de las ilustraciones más icónicas de la historia del pinball. El Terminator mirándote mientras juegas, con ese ojo rojo encendido. Inconfundible desde el otro lado del salón.</p>'),
	(51, 19, 4, 'Schwarzenegger en tus altavoces', '<p>Williams consiguió las voces originales de <strong>Arnold Schwarzenegger</strong> para el pinball. No un imitador, no un doblador — el propio Arnold grabó frases específicamente para la máquina.</p>\r\n\r\n<p>"I\'ll be back." "Hasta la vista, baby." "Come with me if you want to live." Las frases más icónicas de la película suenan desde los altavoces en los momentos exactos del juego. Cuando completas la rampa principal, Arnold lo celebra. Cuando pierdes la bola, te avisa. Cuando activas el multiball, el tono sube a un nivel que hace que la gente del salón se gire a mirar.</p>\r\n\r\n<p>La tecnología de audio de Williams en 1991 era la mejor del mercado — sistema estéreo, efectos de sonido de la película digitalizados a alta calidad, música que sigue el ritmo del juego. En conjunto es una experiencia sonora que muy pocos pinballs de la época podían igualar.</p>\r\n\r\n<hr>\r\n\r\n<p>Hay un momento específico que los jugadores veteranos conocen de memoria: cuando activas el <strong>Multiball</strong> y Arnold grita <em>"Hasta la vista, baby"</em> justo antes de que las tres bolas se lancen simultáneamente. Es uno de esos momentos que hacen que el pinball sea imposible de replicar en ningún otro formato.</p>'),
	(52, 19, 5, 'Modos de juego', '<p>Terminator 2 sigue la filosofía de Ritchie: modos claros, objetivos comprensibles y una escalada de dificultad que engancha desde la primera partida.</p>\r\n\r\n<p><strong>Stroke of Luck</strong> — el modo de arranque. Completar ciertos targets al inicio de la partida activa un multiplicador que afecta a todo lo que viene después. El jugador que lo activa sistemáticamente tiene una ventaja enorme sobre el que no sabe que existe.</p>\r\n\r\n<p><strong>Nuke Multiball</strong> — el modo central de la mesa. Tres bolas simultáneas, el cañón de plasma activo y todos los targets con valor multiplicado. El caos controlado en su máxima expresión.</p>\r\n\r\n<p><strong>Seek and Destroy</strong> — modo de tiempo limitado donde cada target tiene un valor creciente. Requiere velocidad y precisión. Es el modo que separa a los jugadores buenos de los mediocres.</p>\r\n\r\n<p><strong>Judgment Day</strong> — el Wizard Mode. Conseguirlo requiere completar todos los modos principales en una sola partida. Cuando ocurre, la mesa literalmente explota en luces y sonido. Arnold lo celebra como si hubiera ganado la guerra contra Skynet.</p>'),
	(53, 19, 6, 'Treinta años después', '<p>Terminator 2 cumplió treinta años en 2021 y sigue siendo una de las mesas más buscadas por los coleccionistas. No al nivel de The Addams Family o Medieval Madness — esas tienen precios desorbitados — pero T2 en buen estado supera los 5.000€ sin dificultad y la demanda no baja.</p>\r\n\r\n<p>El sistema WPC de Williams es robusto y los repuestos son relativamente fáciles de conseguir. Una T2 bien mantenida puede durar décadas más sin problemas graves. Es una de las razones por las que sigue habiendo tantas en circulación — y en funcionamiento — después de tanto tiempo.</p>\r\n\r\n<p>Para los coleccionistas que quieren iniciarse, T2 es una opción sólida: precio razonable comparado con los grandes clásicos, mantenimiento asequible, piezas disponibles y una jugabilidad que no cansa. No es la mesa más profunda de Williams, pero es una de las más divertidas.</p>\r\n\r\n<blockquote>Hay mesas que impresionan la primera vez. Hay mesas que siguen impresionando la décima. Terminator 2 es de las segundas.</blockquote>');

